-- Schema for Domain: outage | Business: Energy Utilities | Version: v1_mvm
-- Generated on: 2026-05-05 00:40:06

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `energy_utilities_ecm`.`outage` COMMENT 'Outage management including unplanned interruptions, planned maintenance windows, storm response, crew dispatch, restoration prioritization, customer notifications, SAIDI/SAIFI/CAIDI tracking, and OMS integration. Manages outage events, switching orders, service restoration workflows, and reliability performance reporting. Distinct from grid domain (real-time control) — focuses on event lifecycle and restoration coordination.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`event` (
    `event_id` BIGINT COMMENT 'Unique surrogate identifier for each outage event record in the OMS. Primary key for the outage_event data product. Serves as the authoritative SSOT identity key for all downstream joins, lineage, and reporting.',
    `cause_id` BIGINT COMMENT 'Foreign key linking to outage.cause. Business justification: The event table stores cause_code (STRING) and cause_description (STRING) as denormalized text fields. The cause table is the authoritative reference for outage cause classifications. Adding cause_id ',
    `control_area_id` BIGINT COMMENT 'Foreign key linking to grid.control_area. Business justification: Outages within control areas impact ACE, CPS compliance, frequency response obligations, and NERC reporting. Control center operators need to track outage impacts on balancing authority performance me',
    `control_center_id` BIGINT COMMENT 'Foreign key linking to grid.control_center. Business justification: Outage events are operationally managed by a specific control center. NERC TOP/EOP standards require knowing which control center coordinated the outage response. Domain experts expect this link for p',
    `der_system_id` BIGINT COMMENT 'Foreign key linking to interconnection.der_system. Business justification: Outage events must track DER involvement for root cause analysis, IEEE 1547 compliance verification, fault contribution assessment, and regulatory reporting. OMS systems routinely flag DER-related dis',
    `ami_head_end_id` BIGINT COMMENT 'Foreign key linking to metering.ami_head_end. Business justification: Outage events detected via AMI last-gasp must reference the detecting AMI head-end system. event has detection_source (plain text) but no FK. This supports AMI-OMS integration KPI reporting, head-end ',
    `zone_id` BIGINT COMMENT 'Foreign key linking to forecast.zone. Business justification: Outage events occur within forecast zones. Utilities track zone-level outage impacts for load forecast adjustments, reliability index calculations by zone, and regulatory reporting. OMS systems routin',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Outage events must be evaluated against regulatory obligations for NERC/PUC reportability. Compliance officers determine which outages trigger mandatory reporting under specific obligations (NERC EOP,',
    `reliability_index_period_id` BIGINT COMMENT 'Foreign key linking to outage.reliability_index_period. Business justification: Connect each outage event to its reporting period for reliability metrics; many events belong to one reliability_index_period.',
    `service_territory_id` BIGINT COMMENT 'Reference to the regulated service territory within which the outage occurred. Used for PUC regulatory reporting, territory-level reliability benchmarking, and rate case support.',
    `storm_event_id` BIGINT COMMENT 'Reference to the parent storm or severe weather event record when is_storm_event is True. Links individual outage events to the storm event for aggregate storm impact reporting and mutual aid cost tracking.',
    `actual_restoration_timestamp` TIMESTAMP COMMENT 'The Actual Time of Restoration (ATR) — the confirmed timestamp when the last affected customer on this outage event was restored to service. Used as the authoritative end time for SAIDI/SAIFI/CAIDI duration calculations.',
    `affected_customers_commercial` STRING COMMENT 'Number of commercial customer service points affected by this outage event. Subset of customers_affected_count. Used for commercial segment reliability reporting and economic impact estimation.',
    `affected_customers_industrial` STRING COMMENT 'Number of industrial customer service points affected by this outage event. Subset of customers_affected_count. Used for industrial segment reliability reporting and large-customer impact notifications.',
    `affected_customers_residential` STRING COMMENT 'Number of residential customer service points affected by this outage event. Subset of customers_affected_count. Used for customer class-level reliability reporting and equity analysis required by some state PUCs.',
    `caidi_minutes` DECIMAL(18,2) COMMENT 'The Customer Average Interruption Duration Index (CAIDI) for this outage event, representing the average restoration time experienced by affected customers. Calculated as total customer_minutes_interrupted divided by customers_affected_count. Stored at event level for benchmarking.',
    `call_count` STRING COMMENT 'Total number of customer calls or trouble reports received and clustered to this outage event. Used to gauge customer impact severity, prioritize restoration, and assess IVR/call center load during storm events.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the outage event record was first created in the OMS or Silver layer data product. Used for audit trail, data lineage, and SLA tracking of event creation latency.',
    `crew_dispatch_timestamp` TIMESTAMP COMMENT 'Timestamp when the first field crew was dispatched to the outage location. Used to measure dispatch response time (detection_timestamp to crew_dispatch_timestamp) as an operational KPI and for regulatory response time compliance.',
    `crew_on_site_timestamp` TIMESTAMP COMMENT 'Timestamp when the first field crew arrived on-site at the outage location. Used to measure crew travel time and assess field response performance against SLA targets.',
    `critical_facility_flag` BOOLEAN COMMENT 'Indicates whether the outage event affects one or more critical facilities (hospitals, emergency services, water treatment, telecommunications, or other life-safety infrastructure). True triggers elevated priority and mandatory regulatory notification protocols.',
    `customer_minutes_interrupted` DECIMAL(18,2) COMMENT 'Total customer minutes interrupted (CMI) contributed by this outage event, calculated as the sum of interruption duration (minutes) multiplied by customers affected for each restoration segment. Primary input to SAIDI (System Average Interruption Duration Index) calculation.',
    `customers_affected_count` STRING COMMENT 'Total number of customer service points (meters) interrupted by this outage event at peak impact. Used as the primary customer impact metric for SAIFI calculation (interruptions per customer) and regulatory reporting to PUC.',
    `detection_source` STRING COMMENT 'The source or mechanism by which the outage was first detected. Supports analysis of detection method effectiveness and AMI/SCADA investment value. Values: ami_ping (AMI outage notification), scada_alarm (SCADA supervisory alarm), customer_call (inbound customer report), predictive_model (ML-based prediction), field_crew (crew observation), smart_meter_outage_notification (last gasp signal).. Valid values are `ami_ping|scada_alarm|customer_call|predictive_model|field_crew|smart_meter_outage_notification`',
    `detection_timestamp` TIMESTAMP COMMENT 'The principal real-world timestamp when the outage event was first detected or reported, regardless of detection source (AMI ping, SCADA alarm, customer call, or predictive model). This is the authoritative event start time used for SAIDI/SAIFI/CAIDI duration calculations per IEEE 1366.',
    `energy_not_served_mwh` DECIMAL(18,2) COMMENT 'Estimated energy not served (ENS) in MWh due to this outage event, calculated as the product of average load (MW) on the affected circuit and the outage duration (hours). Used for economic impact assessment, IRP planning, and regulatory reporting.',
    `estimated_restoration_timestamp` TIMESTAMP COMMENT 'The Estimated Time to Restoration (ETR) communicated to customers and field crews, representing the predicted date and time by which all affected customers will be restored. Updated dynamically as restoration progresses. Distinct from actual_restoration_timestamp.',
    `event_status` STRING COMMENT 'Current lifecycle status of the outage event within the OMS workflow. Transitions: new (detected, unworked) → in_progress (crew dispatched or switching underway) → restored (all customers re-energized) → closed (event verified and finalized) → cancelled (duplicate or false positive confirmed).. Valid values are `new|in_progress|restored|closed|cancelled`',
    `event_type` STRING COMMENT 'Classification of the outage event per IEEE 1366 definitions: sustained (interruption > 5 minutes), momentary (≤ 5 minutes), planned (scheduled maintenance), major_event_day (MED per IEEE 1366 beta method), or partial (affecting a subset of customers on a circuit). [ENUM-REF-CANDIDATE: sustained|momentary|planned|major_event_day|partial|rolling — promote to reference product if additional types are needed]. Valid values are `sustained|momentary|planned|major_event_day|partial`',
    `fault_location` STRING COMMENT 'Descriptive location of the fault or interruption point on the network (e.g., pole number, span identifier, address nearest to fault). Captured from field crew report or automated fault location indicator (FLI) in the ADMS.',
    `initial_call_receipt_timestamp` TIMESTAMP COMMENT 'Timestamp when the first customer call or report associated with this outage event was received by the Customer Information System (CIS) or IVR. Used for call clustering analysis and detection latency measurement.',
    `is_major_event_day` BOOLEAN COMMENT 'Indicates whether this outage event occurred on a day declared as a Major Event Day (MED) per the IEEE 1366 beta method. MED events are excluded from standard SAIDI/SAIFI calculations and reported separately to PUC. True = MED event; False = normal event.',
    `is_storm_event` BOOLEAN COMMENT 'Indicates whether this outage event was caused by or associated with a declared storm or severe weather event. Storm-flagged events may be subject to separate regulatory reporting thresholds and mutual aid activation criteria.',
    `isolation_method` STRING COMMENT 'Method by which the fault was isolated from the network: automatic (protective device operated automatically), manual (field crew operated device manually), remote (SCADA/ADMS remote switching), or flisr_automated (ADMS FLISR automation executed switching sequence).. Valid values are `automatic|manual|remote|flisr_automated`',
    `nerc_reportable_flag` BOOLEAN COMMENT 'Indicates whether this outage event meets NERC reporting thresholds (e.g., EOP-004 disturbance reporting criteria based on MW loss, customer count, or duration). True = event must be reported to NERC/DOE via OE-417 or equivalent.',
    `notification_sent_flag` BOOLEAN COMMENT 'Indicates whether automated customer outage notifications (IVR, SMS, email, or app push) have been sent for this outage event. True = at least one notification batch dispatched. Used for regulatory compliance tracking of customer communication requirements.',
    `notification_timestamp` TIMESTAMP COMMENT 'Timestamp when the first customer outage notification was dispatched for this event. Used to measure notification latency from detection and to demonstrate compliance with PUC customer communication time requirements.',
    `oms_event_code` STRING COMMENT 'The externally-known event identifier assigned by the Outage Management System (GE PowerOn ADMS). This is the operational business identifier used by field crews, dispatchers, and customer service representatives to reference the outage event across systems.',
    `predicted_cause_code` STRING COMMENT 'The cause code predicted by the OMS predictive model or ADMS fault analysis engine at the time of initial detection, before field crew investigation. Compared against final cause_code for model accuracy tracking. [ENUM-REF-CANDIDATE: weather|equipment_failure|animal_contact|vegetation|human_error|unknown — promote to reference product]',
    `predicted_customers_affected` STRING COMMENT 'The number of customers predicted to be affected by the outage at the time of initial detection, as estimated by the OMS/ADMS predictive model. Compared against actual customers_affected_count for model accuracy and ETR calibration.',
    `prediction_confidence_score` DECIMAL(18,2) COMMENT 'Confidence score (0.00–100.00) assigned by the predictive model or ADMS fault analysis engine to the initial outage prediction, including predicted cause and affected scope. Used to assess model reliability and calibrate automated dispatch thresholds.',
    `priority_level` STRING COMMENT 'Restoration priority classification assigned to the outage event, used to sequence crew dispatch and switching operations. Critical: hospitals, emergency services, critical infrastructure; High: large commercial/industrial, high customer count; Medium: standard residential; Low: single-customer or non-critical.. Valid values are `critical|high|medium|low`',
    `puc_reportable_flag` BOOLEAN COMMENT 'Indicates whether this outage event meets the state Public Utility Commission (PUC) threshold for mandatory individual event reporting (e.g., exceeds customer count or duration thresholds defined in the utilitys tariff or service quality rules).',
    `reported_symptom` STRING COMMENT 'The primary symptom reported by the first customer caller or detected by the AMI/SCADA system at the time of initial report. Used for triage, cause hypothesis, and crew dispatch guidance.. Valid values are `no_power|flickering|partial_power|low_voltage|high_voltage|other`',
    `saidi_contribution_minutes` DECIMAL(18,2) COMMENT 'This events contribution to the System Average Interruption Duration Index (SAIDI), expressed in customer-minutes per total customers served. Calculated as customer_minutes_interrupted divided by total customers served in the reporting period. Stored at event level for regulatory period aggregation.',
    `saifi_contribution` DECIMAL(18,2) COMMENT 'This events contribution to the System Average Interruption Frequency Index (SAIFI), expressed as customer interruptions per total customers served. Calculated as customers_affected_count divided by total customers served. Stored at event level for regulatory period aggregation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the outage event record. Supports change detection, incremental ETL processing, and audit compliance.',
    CONSTRAINT pk_event PRIMARY KEY(`event_id`)
) COMMENT 'Core master record for every unplanned or planned power interruption event managed by the OMS. Captures the full lifecycle from initial detection (via AMI ping, SCADA alarm, customer call clustering, or predictive model) through final restoration. Includes cause classification, outage type (sustained, momentary, planned, major event per IEEE 1366), affected circuit/feeder, estimated vs. actual restoration time (ETR/ATR), initial prediction metadata (source, confidence, predicted scope, predicted cause, predicted affected segments), source call/report metadata (call receipt timestamp, source type, reported symptom, call disposition, duplicate flag, call clustering results), lifecycle status transitions with full audit trail (status code, transition timestamp, triggering actor, status notes), affected network segment detail (segment identifier, type, de-energization timestamps, isolation method, customer count, restoration sequence priority), SAIDI/SAIFI/CAIDI contribution, storm flag, Major Event Day declaration status, and OMS event identifier. This is the authoritative SSOT for outage event identity, lifecycle, initial prediction, source reporting, status history, and segment-level impact in the outage domain.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`interruption` (
    `interruption_id` BIGINT COMMENT 'Unique surrogate identifier for a single customer or premise-level service interruption record. Primary key for this entity.',
    `account_id` BIGINT COMMENT 'Reference to the customer account associated with the interrupted service point at the time of the interruption. Supports customer-facing outage communication and regulatory customer impact reporting.',
    `meter_id` BIGINT COMMENT 'The AMI meter identifier associated with the service point at the time of the interruption. Used to correlate last-gasp and first-breath AMI signals from the MDM system for automated interruption detection and restoration confirmation.',
    `billing_service_agreement_id` BIGINT COMMENT 'Foreign key linking to billing.billing_service_agreement. Business justification: Individual customer interruptions require service agreement context to apply correct credit calculation rules based on rate schedule, service class, and contractual SLA terms. Enables automated credit',
    `cause_id` BIGINT COMMENT 'FK to outage.cause',
    `crew_dispatch_id` BIGINT COMMENT 'Reference to the field crew dispatch record associated with the restoration of this interruption. Links to workforce management for crew response time analysis and restoration efficiency reporting.',
    `der_system_id` BIGINT COMMENT 'Foreign key linking to interconnection.der_system. Business justification: Customer interruptions at DER-equipped service points require DER system reference for islanding analysis, restoration sequencing, and regulatory reporting of DER performance during grid disturbances ',
    `distribution_substation_id` BIGINT COMMENT 'Reference to the substation serving the affected service point at the time of the interruption. Supports substation-level reliability performance reporting and outage root cause analysis.',
    `event_id` BIGINT COMMENT 'Reference to the parent outage event that caused this customer-level interruption. Links the granular interruption record to the broader outage event for SAIDI/SAIFI/CAIDI roll-up calculations.',
    `feeder_id` BIGINT COMMENT 'Reference to the distribution feeder circuit that serves the affected service point. Supports feeder-level reliability analysis, SAIDI/SAIFI benchmarking by circuit, and GIS-based outage mapping.',
    `planned_outage_window_id` BIGINT COMMENT 'Reference to the planned maintenance window associated with this interruption, when applicable. Null for unplanned outages. Links to the planned outage schedule for customer notification and regulatory reporting.',
    `meter_point_id` BIGINT COMMENT 'Foreign key linking to metering.meter_point. Business justification: Interruptions must reference the meter_point (AMI collection point) directly for interval data gap analysis, automated outage detection via AMI, and SAIDI/SAIFI calculations at the meter_point level. ',
    `outage_switching_order_id` BIGINT COMMENT 'Reference to the switching order executed to isolate or restore the affected circuit segment. Links the customer-level interruption to the operational switching workflow in the ADMS/OMS.',
    `service_point_id` BIGINT COMMENT 'Reference to the specific service delivery point (meter point or premise connection) that experienced the interruption. The fundamental unit of interruption tracking per IEEE 1366.',
    `service_territory_id` BIGINT COMMENT 'FK to distribution.service_territory',
    `to_planned_outage_window_id` BIGINT COMMENT 'FK to outage.planned_outage_window.planned_outage_window_id — Customer interruptions from planned maintenance link to the planned outage window. Required for distinguishing planned vs unplanned interruptions in reliability reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this interruption record was first created in the system, either by automated OMS event processing or manual dispatcher entry. Supports audit trail and data lineage requirements.',
    `critical_care_type` STRING COMMENT 'Specific category of critical care designation for the affected customer. Used to prioritize restoration sequencing and determine notification requirements. Only populated when is_critical_care is true.. Valid values are `medical_baseline|life_support|dialysis|oxygen_dependent|none`',
    `customer_class` STRING COMMENT 'Classification of the affected customer by service class at the time of the interruption. Used for segmented SAIDI/SAIFI/CAIDI reporting by customer class as required by state PUC reliability standards and NERC reporting.. Valid values are `residential|commercial|industrial|agricultural|government`',
    `customers_affected_count` STRING COMMENT 'Number of customers affected by the parent outage event at the time this interruption record was created. Denormalized from the outage event for regulatory reporting convenience. Used in SAIFI numerator calculations and NERC/PUC customer impact reporting.',
    `data_quality_flag` STRING COMMENT 'Indicates the data quality status of this interruption record as assessed during Silver layer validation. validated indicates all timestamps and durations are confirmed; estimated indicates one or more fields are estimated; suspect indicates anomalies detected; corrected indicates the record has been manually revised post-initial capture.. Valid values are `validated|estimated|suspect|corrected`',
    `duration_minutes` STRING COMMENT 'Total duration of the service interruption in whole minutes, calculated as the difference between interruption_end_timestamp and interruption_start_timestamp. Stored as a business field to support SAIDI and CAIDI reliability index calculations without requiring real-time computation. Null if interruption is still active.',
    `end_timestamp` TIMESTAMP COMMENT 'Date and time when the customers service was restored, recorded to millisecond precision. Null if the interruption is still active. Used as the end point for duration calculations and CAIDI index computation per IEEE 1366.',
    `estimated_restoration_timestamp` TIMESTAMP COMMENT 'Estimated date and time of service restoration communicated to the customer and used for crew scheduling. Distinct from interruption_end_timestamp (actual restoration). Supports customer communication accuracy tracking and ETR (Estimated Time to Restore) performance measurement.',
    `interruption_status` STRING COMMENT 'Current lifecycle state of the interruption record. active indicates the customer is currently without power; restored indicates service has been re-energized; cancelled indicates the interruption was logged in error; pending_confirmation indicates restoration has been initiated but field confirmation is outstanding.. Valid values are `active|restored|cancelled|pending_confirmation`',
    `interruption_type` STRING COMMENT 'Classification of the interruption as planned (scheduled maintenance), unplanned (forced outage), or momentary (duration less than 5 minutes per IEEE 1366 definition). Drives separate SAIDI/SAIFI/MAIFI index tracking and regulatory reporting segmentation.. Valid values are `planned|unplanned|momentary`',
    `is_critical_care` BOOLEAN COMMENT 'Indicates whether the affected customer or premise is designated as a critical care account (medical baseline, life support equipment, or other medically vulnerable designation). Critical care customers receive priority restoration and mandatory advance notification under state PUC rules.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this interruption record was most recently modified, including status updates, restoration confirmation, or cause code revisions. Supports change tracking and Silver layer incremental processing.',
    `major_event_day_exclusion` BOOLEAN COMMENT 'Indicates whether this interruption has been formally excluded from the standard SAIDI/SAIFI reliability index calculations under the IEEE 1366 Major Event Day beta method. Distinct from storm_event_flag — this is the formal regulatory exclusion determination.',
    `momentary_flag` BOOLEAN COMMENT 'Indicates whether this interruption qualifies as a momentary interruption (duration less than 5 minutes per IEEE 1366 definition). Momentary interruptions are tracked separately for MAIFI (Momentary Average Interruption Frequency Index) calculations.',
    `notification_channel` STRING COMMENT 'Communication channel used to deliver the outage notification to the affected customer. Supports multi-channel notification analytics and customer preference compliance reporting.. Valid values are `sms|email|ivr|mobile_app|none`',
    `notification_opt_out` BOOLEAN COMMENT 'Indicates whether the customer has opted out of outage notifications for this service point. When true, notification_sent will be false by design. Supports customer preference management and regulatory opt-out compliance.',
    `notification_sent` BOOLEAN COMMENT 'Indicates whether an outage notification has been sent to the affected customer for this interruption. Supports regulatory compliance tracking for customer notification requirements mandated by state PUCs.',
    `notification_timestamp` TIMESTAMP COMMENT 'Date and time when the outage notification was dispatched to the customer. Used to measure notification lead time relative to interruption start and to demonstrate regulatory compliance with advance notice requirements for planned outages.',
    `oms_event_number` STRING COMMENT 'The externally-known event number assigned by the Outage Management System (GE PowerOn ADMS) to the parent outage event. Serves as the cross-system integration key for reconciliation between OMS, CIS, and MDM systems.',
    `protective_device_operation` STRING COMMENT 'Type of protective device that operated to isolate the fault causing this interruption. Supports equipment performance analysis, recloser operation tracking, and fuse-saving vs. trip-and-reclose strategy evaluation.. Valid values are `fuse|recloser|breaker|sectionalizer|none`',
    `reference_number` STRING COMMENT 'Externally visible alphanumeric reference number assigned to this interruption record, used in customer communications, regulatory filings, and OMS integration. Format: INT-YYYY-NNNNNNNN.. Valid values are `^INT-[0-9]{4}-[0-9]{8}$`',
    `regulatory_reportable` BOOLEAN COMMENT 'Indicates whether this interruption must be included in regulatory reliability reports submitted to NERC, FERC, or state PUCs. Interruptions below minimum duration thresholds or excluded under MED rules may be flagged as non-reportable.',
    `restoration_confirmation_method` STRING COMMENT 'Method by which service restoration was confirmed. AMI ping uses Advanced Metering Infrastructure last-gasp/first-breath signals; field_crew indicates on-site verification; customer_callback indicates customer-reported restoration; scada indicates SCADA system re-energization signal; estimated indicates restoration assumed based on switching operations.. Valid values are `ami_ping|field_crew|customer_callback|scada|estimated`',
    `restoration_confirmed` BOOLEAN COMMENT 'Indicates whether service restoration has been confirmed for this interruption, either through AMI meter ping, field crew confirmation, or customer callback. Distinguishes between estimated restoration and verified restoration for CAIDI accuracy.',
    `restoration_method` STRING COMMENT 'Method used to restore service to the affected customer or premise. Supports operational analysis of restoration efficiency and crew dispatch effectiveness. [ENUM-REF-CANDIDATE: switching|repair|bypass|auto_reclosure|manual_transfer|temporary_generation — promote to reference product if additional values are needed]. Valid values are `switching|repair|bypass|auto_reclosure|manual_transfer|temporary_generation`',
    `saidi_contribution_minutes` DECIMAL(18,2) COMMENT 'This interruptions individual contribution to the SAIDI reliability index, expressed in customer-minutes divided by total customers served. Stored as a pre-computed business field to support regulatory reporting aggregation without requiring full recalculation. Null if interruption is active or excluded from SAIDI.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this interruption record originated. Supports data lineage, reconciliation, and Silver layer provenance tracking across OMS, CIS, and MDM source systems.. Valid values are `GE_PowerOn_ADMS|Oracle_CC&B|SAP_ISU|Oracle_MDM|manual`',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the customers service interruption began, recorded to millisecond precision. This is the principal business event timestamp used as the start point for duration calculations and SAIDI/SAIFI index computation per IEEE 1366.',
    `storm_event_flag` BOOLEAN COMMENT 'Indicates whether this interruption occurred during a declared major event or storm. When true, the interruption may be excluded from IEEE 1366 Major Event Day (MED) calculations per the beta method, affecting SAIDI/SAIFI index reporting.',
    `to_outage_event` BIGINT COMMENT 'FK to outage.outage_event.outage_event_id — Every customer-level interruption must link to its parent outage event. This is the foundational relationship for SAIDI/SAIFI/CAIDI calculation — without it, reliability indices cannot be computed. Da',
    `voltage_level` STRING COMMENT 'Voltage classification of the circuit segment at which the interruption originated. Used to segment reliability reporting by voltage class and to identify transmission vs. distribution-level outage impacts for FERC and state PUC reporting.. Valid values are `transmission|subtransmission|primary_distribution|secondary_distribution`',
    `weather_condition` STRING COMMENT 'Prevailing weather condition at the time and location of the interruption. Used for weather-normalized reliability analysis, storm response performance reporting, and climate resilience planning. [ENUM-REF-CANDIDATE: clear|wind|ice|snow|lightning|flood|extreme_heat|none — promote to reference product if additional values needed]',
    CONSTRAINT pk_interruption PRIMARY KEY(`interruption_id`)
) COMMENT 'Granular record of a single customer or premise-level service interruption linked to a parent outage event or planned maintenance window. Tracks the specific service point, customer account reference, interruption start and end timestamps, duration in minutes, cause code, restoration method (switching, repair, bypass), planned/unplanned flag, notification sent flag, notification channel, critical care designation (medical baseline, life support), restoration confirmation, and association to planned maintenance windows. Also serves as the customer-outage association record capturing per-customer impact including notification delivery status and opt-out preferences. This is the single SSOT for ALL customer-level outage impact — feeds SAIDI, SAIFI, and CAIDI reliability index calculations, supports customer-facing outage communication, drives regulatory customer impact reporting, and provides the definitive record of which customers were affected by each event.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`outage_switching_order` (
    `outage_switching_order_id` BIGINT COMMENT 'Unique surrogate identifier for the switching order record in the Silver Layer lakehouse. Primary key for this entity.',
    `feeder_id` BIGINT COMMENT 'Identifier of the primary distribution feeder circuit affected by this switching order. Used for network topology analysis, outage impact assessment, and GIS integration with Esri ArcGIS Utility Network.',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to interconnection.interconnection_agreement. Business justification: Switching orders for DER isolation during outages must reference interconnection agreements to verify parallel operation permissions, export limitations, and required notification procedures per tarif',
    `contingency_analysis_run_id` BIGINT COMMENT 'Foreign key linking to grid.contingency_analysis_run. Business justification: Outage switching orders for transmission elements require a contingency analysis run to validate N-1 compliance before execution. NERC TOP-001 requires operators to verify contingency analysis before ',
    `control_area_id` BIGINT COMMENT 'Foreign key linking to grid.control_area. Business justification: Switching orders affect control area operations (state estimation, interchange schedules, AGC). EMS operators coordinate switching with field crews to maintain system reliability and balancing authori',
    `der_system_id` BIGINT COMMENT 'Foreign key linking to interconnection.der_system. Business justification: Switching orders require DER isolation verification before energization per IEEE 1547 and utility operating procedures. Operators must confirm DER status (online/offline/isolated) before executing swi',
    `distribution_substation_id` BIGINT COMMENT 'Reference to the substation from which the affected feeder originates or where the primary switching devices are located. Used for geographic scoping and asset management integration.',
    `event_id` BIGINT COMMENT 'Reference to the parent outage event that triggered this switching order. Links the switching sequence to the originating interruption or planned maintenance event in the Outage Management System (OMS).',
    `grid_switching_order_id` BIGINT COMMENT 'Foreign key linking to grid.grid_switching_order. Business justification: Outage switching orders may reference or be coordinated with grid switching orders for transmission-connected substations. Linking enables cross-system switching coordination and safety compliance.',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Switching orders on critical infrastructure require compliance documentation under NERC CIP or operational reliability standards. Operations must document adherence to switching protocols mandated by ',
    `operating_limit_id` BIGINT COMMENT 'Foreign key linking to grid.operating_limit. Business justification: Switching orders must be validated against operating limits (thermal/voltage) before execution. NERC FAC-001/FAC-002 compliance requires operators to verify limits are not exceeded during planned de-e',
    `planned_outage_window_id` BIGINT COMMENT 'Foreign key linking to outage.planned_outage_window. Business justification: The outage_switching_order table has planned_outage_flag (BOOLEAN) indicating the switching order is for a planned outage, but no FK to the planned_outage_window record. Switching orders are the prima',
    `poi_specification_id` BIGINT COMMENT 'Foreign key linking to interconnection.poi_specification. Business justification: Switching orders affecting DER interconnection points must reference POI specifications for proper isolation procedures, disconnect switch operation, metering configuration, and safe re-energization s',
    `registry_id` BIGINT COMMENT 'Foreign key linking to asset.registry. Business justification: Switching orders specify which physical switching device must be operated to isolate circuits. Safety clearance procedures require explicit asset identification. Operations teams need asset-specific o',
    `state_estimation_run_id` BIGINT COMMENT 'Foreign key linking to grid.state_estimation_run. Business justification: Outage switching orders reference the state estimation snapshot used to validate network conditions at time of execution. NERC TOP-001 requires operators to use current network state before switching.',
    `storm_event_id` BIGINT COMMENT 'Foreign key linking to outage.storm_event. Business justification: The outage_switching_order table has storm_event_flag (BOOLEAN) indicating the switching order is storm-related, but no FK to the storm_event master record. During storm response, switching orders are',
    `weather_input_id` BIGINT COMMENT 'Foreign key linking to forecast.weather_input. Business justification: Switching orders executed during adverse weather require real-time weather context for crew safety protocols, hazard assessment, and operational decision-making. Weather conditions directly impact swi',
    `actual_customers_affected` STRING COMMENT 'The confirmed number of customer service points that were interrupted as a result of this switching order, validated post-restoration. Used for SAIDI/SAIFI/CAIDI reliability metric calculation and regulatory reporting to State PUCs.',
    `actual_end_timestamp` TIMESTAMP COMMENT 'The actual date and time when the final switching step was completed and the switching order was closed. Used for outage duration calculation and SAIDI/SAIFI/CAIDI reliability performance reporting.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'The actual date and time when the field crew began executing the first step of the switching sequence. Used for SAIDI/SAIFI/CAIDI reliability metric calculation and post-event analysis.',
    `adms_switching_order_ref` STRING COMMENT 'The native switching order identifier assigned by the GE PowerOn Advanced Distribution Management System (ADMS). Used for cross-system reconciliation between the Silver Layer lakehouse and the operational ADMS source system.',
    `approval_chain_notes` STRING COMMENT 'Free-text notes documenting the approval chain for this switching order, including any conditional approvals, escalations, or deviations from standard authorization procedures. Supports NERC compliance audit trail.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when the switching order received final authorization from the approving supervisor or operations manager. Part of the approval chain audit trail required for NERC compliance.',
    `cancellation_reason` STRING COMMENT 'Free-text explanation of why this switching order was cancelled, if applicable. Populated only when order_status is cancelled. Supports post-event analysis and process improvement.',
    `completed_steps_count` STRING COMMENT 'The number of individual switching steps that have been successfully executed and confirmed as of the last update. Enables real-time progress monitoring during active switching operations.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this switching order record was first created in the system, which may precede the issued timestamp if the order was drafted in advance. Used for audit trail and data lineage.',
    `customer_notification_sent_flag` BOOLEAN COMMENT 'Indicates whether advance customer notification was sent for this switching order (applicable to planned outages). Supports compliance tracking against State PUC advance notification requirements, typically 48-72 hours prior to planned interruption.',
    `de_energization_timestamp` TIMESTAMP COMMENT 'The date and time when the affected network segment was de-energized (taken out of service) as part of this switching order. Critical for outage duration measurement and SAIDI calculation start point.',
    `energization_timestamp` TIMESTAMP COMMENT 'The date and time when the affected network segment was re-energized (returned to service) following completion of the switching sequence. Marks the end of the customer interruption for SAIDI/CAIDI calculation.',
    `estimated_customers_affected` STRING COMMENT 'The estimated number of customer service points that will be or are interrupted as a result of this switching order. Used for customer notification prioritization, regulatory reporting, and SAIFI calculation inputs.',
    `hazard_notes` STRING COMMENT 'Free-text field capturing known hazards, special safety precautions, or environmental conditions relevant to executing this switching order. Examples include downed conductors, flooded equipment, or proximity to energized lines. Mandatory review by crew before execution.',
    `issued_timestamp` TIMESTAMP COMMENT 'The date and time when the dispatcher formally issued this switching order to the field crew. This is the principal business event timestamp marking the start of the switching order lifecycle. Recorded in ISO 8601 format with timezone offset.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this switching order record was most recently modified. Tracks any changes to the order after initial creation, supporting audit trail requirements.',
    `nerc_reportable_flag` BOOLEAN COMMENT 'Indicates whether this switching order is associated with an event that meets NERC reportability thresholds (e.g., EOP-004 disturbance reporting). When True, the event must be included in mandatory NERC regulatory submissions.',
    `network_segment_description` STRING COMMENT 'Human-readable description of the distribution or transmission network segment affected by this switching order, including feeder name, circuit section, and geographic reference. Supports field crew orientation and post-event reporting.',
    `oms_incident_number` STRING COMMENT 'The incident or trouble call number from the Outage Management System (OMS) associated with this switching order. Enables traceability from the switching sequence back to the originating customer-reported outage or system-detected fault.',
    `order_status` STRING COMMENT 'Current lifecycle state of the switching order. Tracks progression from initial drafting through dispatcher issuance, field execution, and final completion or cancellation. Drives workflow routing in GE PowerOn ADMS.. Valid values are `draft|issued|in_progress|completed|cancelled|suspended`',
    `order_type` STRING COMMENT 'Classification of the switching order by operational purpose. Distinguishes planned maintenance windows from emergency outage restoration, storm response, load transfer operations, and asset commissioning/decommissioning activities. [ENUM-REF-CANDIDATE: planned_maintenance|emergency_restoration|storm_response|load_transfer|commissioning|decommissioning — promote to reference product]. Valid values are `planned_maintenance|emergency_restoration|storm_response|load_transfer|commissioning|decommissioning`',
    `planned_outage_flag` BOOLEAN COMMENT 'Indicates whether this switching order is associated with a planned (scheduled) outage as opposed to an unplanned (forced) interruption. Planned outages are tracked separately for SAIDI/SAIFI reporting and customer advance notification compliance.',
    `post_event_review_flag` BOOLEAN COMMENT 'Indicates whether this switching order has been flagged for mandatory post-event review, typically triggered by NERC reportable events, major storm response, or switching errors. Drives the post-event analysis workflow.',
    `post_event_review_notes` STRING COMMENT 'Free-text findings and corrective actions documented during the post-event review of this switching order. Populated after review completion when post_event_review_flag is True. Supports continuous improvement and regulatory compliance.',
    `priority_level` STRING COMMENT 'Operational priority assigned to this switching order, used for restoration prioritization and crew dispatch sequencing. Critical priority is reserved for transmission-level or large-scale customer impact events.. Valid values are `critical|high|medium|low`',
    `restoration_method` STRING COMMENT 'The method used to restore service as part of this switching order. Distinguishes manual field crew switching from automated ADMS-driven Fault Location, Isolation, and Service Restoration (FLISR), remote switching via SCADA, sectionalizing, or load transfer to alternate feeders.. Valid values are `manual|automatic_flisr|remote_switching|sectionalizing|load_transfer`',
    `safety_clearance_number` STRING COMMENT 'The reference number of the safety clearance (hold tag or clearance order) associated with this switching order. Ensures that de-energized equipment is properly tagged and locked out before crew work begins. Mandatory for OSHA lockout/tagout compliance.. Valid values are `^CLR-[0-9]{4}-[0-9]{6}$`',
    `scheduled_end_timestamp` TIMESTAMP COMMENT 'The planned date and time by which the switching sequence is expected to be completed and the network restored to target configuration. Used for outage duration estimation and customer notification.',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'The planned date and time for field crew to begin executing the switching sequence. Used for planned maintenance scheduling and crew coordination. May differ from actual execution start time.',
    `storm_event_flag` BOOLEAN COMMENT 'Indicates whether this switching order was issued in response to a major storm or declared emergency event. When True, the associated outage duration may be excluded from IEEE Std 1366 SAIDI/SAIFI calculations per major event day (MED) criteria.',
    `suspension_reason` STRING COMMENT 'Free-text explanation of why this switching order was suspended mid-execution, if applicable. Populated only when order_status is suspended. Common reasons include unexpected hazards, equipment failure, or crew safety concerns.',
    `switching_order_number` STRING COMMENT 'Externally-known alphanumeric identifier for the switching order, used by dispatchers, field crews, and control room operators. Format: SO-{YYYY}-{NNNNNN}. This is the business-facing reference number used in OMS and ADMS systems.. Valid values are `^SO-[0-9]{4}-[0-9]{6}$`',
    `switching_purpose_description` STRING COMMENT 'Free-text description of the operational reason for issuing this switching order, including the specific fault, maintenance activity, or load transfer objective. Provides context beyond the structured order_type classification.',
    `switching_zone` STRING COMMENT 'The operational control zone or dispatch territory within which this switching order is executed. Aligns with the utilitys geographic service territory divisions used for crew dispatch and reliability performance reporting.',
    `total_steps_count` STRING COMMENT 'The total number of individual switching steps defined in this switching order sequence. Used for progress tracking and completeness validation during execution.',
    `version` STRING COMMENT 'Version number of this switching order, incremented each time the order is revised after initial issuance. Supports audit trail requirements and ensures field crews are executing the most current approved version of the switching sequence.',
    `voltage_level_kv` DECIMAL(18,2) COMMENT 'The nominal operating voltage level in kilovolts (kV) of the network segment affected by this switching order. Determines applicable safety procedures, crew qualifications, and regulatory requirements.',
    `work_order_number` STRING COMMENT 'Reference to the associated maintenance or repair work order in the asset management system (Ventyx Asset Suite or SAP S/4HANA Plant Maintenance). Links the switching order to the underlying maintenance activity that necessitated the switching sequence.',
    CONSTRAINT pk_outage_switching_order PRIMARY KEY(`outage_switching_order_id`)
) COMMENT 'Formal switching order issued during outage restoration or planned maintenance to reconfigure the distribution network. Captures the complete switching sequence including individual step detail (step sequence number, device identifier, device type, action type — open/close/tag/verify, required safety state, completion status, actual execution timestamp, executing crew member). Also records issuing dispatcher, executing crew, affected switching devices (sectionalizers, reclosers, breakers), safety clearance references, energization/de-energization timestamps, and approval chain. Supports granular audit trail of switching sequences for NERC compliance and post-event analysis. Integrates with GE PowerOn ADMS switching management module.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`crew_dispatch` (
    `crew_dispatch_id` BIGINT COMMENT 'Unique surrogate identifier for each crew dispatch record within the outage management system. Primary key for the crew_dispatch data product.',
    `control_area_id` BIGINT COMMENT 'Foreign key linking to grid.control_area. Business justification: Crew dispatches to transmission-connected substations affect control area operations. Coordination between field crews and control center operators is essential for safe switching and maintaining syst',
    `der_system_id` BIGINT COMMENT 'Foreign key linking to interconnection.der_system. Business justification: Crew dispatches to DER locations require system details for safety clearances, anti-islanding verification, lockout/tagout procedures, and coordination with customer-owned generation per OSHA and util',
    `ems_node_id` BIGINT COMMENT 'Foreign key linking to grid.ems_node. Business justification: Crew dispatches for transmission-level outages target specific EMS network nodes. The EMS node identifies the precise substation bus or network element requiring field crew work. Domain experts expect',
    `event_id` BIGINT COMMENT 'Reference to the outage event that triggered this crew dispatch. Links the dispatch record to the parent outage lifecycle managed in the Outage Management System (OMS).',
    `zone_id` BIGINT COMMENT 'Foreign key linking to forecast.zone. Business justification: Crew dispatches are assigned to forecast zones for resource tracking, mutual aid coordination, and operational planning. Utilities use zone-level crew deployment data for storm response planning, reso',
    `grid_switching_order_id` BIGINT COMMENT 'Foreign key linking to grid.grid_switching_order. Business justification: Crew dispatches execute grid switching orders. Linking enables tracking of switching order execution status, crew assignment, and field crew coordination with control center operators.',
    `mutual_aid_request_id` BIGINT COMMENT 'Foreign key linking to outage.mutual_aid_request. Business justification: The outage_crew_dispatch table has mutual_aid_flag (BOOLEAN) indicating the crew is a mutual aid crew, but no FK to the mutual_aid_request record. Mutual aid crews are dispatched under a formal mutual',
    `restoration_action_id` BIGINT COMMENT 'Reference to the specific restoration action or switching order this dispatch is fulfilling. Enables traceability from dispatch to restoration workflow step.',
    `storm_event_id` BIGINT COMMENT 'Foreign key linking to outage.storm_event. Business justification: The outage_crew_dispatch table has storm_event_flag (BOOLEAN) indicating the dispatch is storm-related, but no FK to the storm_event master record. During major storm events, crew dispatches are manag',
    `registry_id` BIGINT COMMENT 'Foreign key linking to asset.registry. Business justification: Crew dispatches target specific failed assets (failed transformer, downed conductor, damaged pole). Dispatch systems communicate asset identity to crews for spare parts selection, specialized tools, a',
    `actual_arrival_at` TIMESTAMP COMMENT 'Actual timestamp when the crew arrived at the outage location and confirmed on-site presence. Captured via mobile device check-in or OMS field update. Used to measure travel time actuals vs. estimates.',
    `actual_restoration_at` TIMESTAMP COMMENT 'Timestamp when power was actually restored to affected customers following crew repair work. Used as the definitive restoration time for SAIDI (System Average Interruption Duration Index) and CAIDI (Customer Average Interruption Duration Index) calculations.',
    `cancellation_reason` STRING COMMENT 'Reason code for dispatch cancellation when dispatch_status is cancelled. Captures why the crew was stood down before completing the assignment (e.g., outage restored via FLISR/remote switching, duplicate dispatch, crew reassigned to higher priority). [ENUM-REF-CANDIDATE: duplicate_dispatch|outage_restored_remotely|crew_reassigned|weather_stand_down|customer_cancelled|other — promote to reference product]. Valid values are `duplicate_dispatch|outage_restored_remotely|crew_reassigned|weather_stand_down|customer_cancelled|other`',
    `cause_code` STRING COMMENT 'Standardized cause code assigned by the crew upon arrival or completion, classifying the root cause of the outage (e.g., equipment failure, tree contact, animal contact, weather, vehicle accident). Aligns with IEEE 1366 cause code taxonomy for reliability reporting.',
    `cleared_at` TIMESTAMP COMMENT 'Timestamp when the crew was formally released from the outage site and cleared for reassignment. May differ from work_completed_at if post-work safety checks, documentation, or switching order closeout is required.',
    `contractor_company_name` STRING COMMENT 'Name of the external contractor company providing the crew, when crew_type is contractor or mutual_aid_flag is true. Used for contractor performance tracking, invoice reconciliation, and mutual aid cost recovery.',
    `created_at` TIMESTAMP COMMENT 'Timestamp when the crew dispatch record was first created in the Outage Management System (OMS). Used for audit trail and data lineage tracking.',
    `crew_identifier` STRING COMMENT 'Human-readable operational identifier for the dispatched crew (e.g., crew badge number, radio call sign, or crew unit code) as used by dispatchers and field supervisors in OMS communications.',
    `crew_size` STRING COMMENT 'Number of personnel included in the dispatched crew. Used for resource planning, storm response staffing analytics, and mutual aid tracking.',
    `crew_type` STRING COMMENT 'Classification of the dispatched crew by functional role and capability. Determines the type of work the crew is qualified to perform at the outage site. [ENUM-REF-CANDIDATE: line_crew|troubleshooter|contractor|tree_crew|substation_crew|damage_assessment — promote to reference product]. Valid values are `line_crew|troubleshooter|contractor|tree_crew|substation_crew|damage_assessment`',
    `critical_facility_flag` BOOLEAN COMMENT 'Indicates whether the outage site or affected area includes a critical facility (e.g., hospital, emergency services, water treatment plant, military installation). Drives elevated dispatch priority and regulatory notification requirements.',
    `customers_affected_count` STRING COMMENT 'Number of customer service points affected by the outage event at the time of dispatch. Used for prioritization, regulatory reporting, and SAIFI (System Average Interruption Frequency Index) calculations.',
    `damage_assessment_code` STRING COMMENT 'Field crew assessment of infrastructure damage severity at the outage site. Used for storm response resource planning, mutual aid requests, and post-event damage reporting to regulators.. Valid values are `none|minor|moderate|major|catastrophic`',
    `dispatch_location_description` STRING COMMENT 'Free-text description of the outage site location provided to the crew at dispatch time, including landmarks, access instructions, or hazard notes. Supplements GIS coordinates for field navigation.',
    `dispatch_number` STRING COMMENT 'Externally-known alphanumeric identifier for the dispatch record, used by field crews, dispatchers, and OMS operators for cross-system reference and communication. Format: DSP-YYYY-NNNNNN.. Valid values are `^DSP-[0-9]{4}-[0-9]{6}$`',
    `dispatch_priority` STRING COMMENT 'Priority tier assigned to this dispatch, reflecting urgency based on outage impact (e.g., critical infrastructure, hospital, large customer count). Drives restoration sequencing and resource allocation decisions.. Valid values are `critical|high|medium|low`',
    `dispatch_source` STRING COMMENT 'Originating channel or system through which the dispatch was initiated. Distinguishes automated OMS-driven dispatches from manual dispatcher assignments, storm center activations, or mutual aid requests.. Valid values are `oms_auto|dispatcher_manual|storm_center|mutual_aid|contractor_portal`',
    `dispatch_status` STRING COMMENT 'Current lifecycle state of the crew dispatch record, tracking progression from initial assignment through field completion. [ENUM-REF-CANDIDATE: pending|dispatched|en_route|on_site|work_in_progress|completed|cancelled — promote to reference product]',
    `dispatched_at` TIMESTAMP COMMENT 'The principal real-world event timestamp when the crew was formally dispatched from the operations center to the outage location. Used as the primary business event time for SAIDI/SAIFI/CAIDI reliability metric calculations.',
    `dispatcher_notes` STRING COMMENT 'Free-text notes entered by the dispatcher at the time of crew assignment, including special instructions, hazard warnings, customer contact information, or access restrictions for the outage site.',
    `estimated_arrival_at` TIMESTAMP COMMENT 'Calculated timestamp for when the crew is expected to arrive on-site at the outage location. Derived at dispatch time from dispatched_at plus estimated_travel_time_min. Used for customer ETR (Estimated Time to Restore) communications.',
    `estimated_restoration_at` TIMESTAMP COMMENT 'Estimated Time to Restore (ETR) as assessed by the crew or dispatcher after on-site evaluation. Used for customer notification updates and regulatory ETR reporting requirements. Distinct from estimated_arrival_at.',
    `estimated_travel_time_min` STRING COMMENT 'Estimated travel time in minutes from the crews current location or staging area to the outage site at the time of dispatch. Used for restoration time estimation and customer notification ETAs.',
    `field_crew_notes` STRING COMMENT 'Free-text notes entered by the field crew upon arrival or completion, documenting observed conditions, equipment findings, repair actions taken, or follow-up work required. Captured via mobile OMS interface.',
    `follow_up_required_flag` BOOLEAN COMMENT 'Indicates whether the crew identified additional work required beyond the initial restoration scope (e.g., permanent repair after temporary restoration, equipment replacement, vegetation management). Triggers follow-up work order creation.',
    `mutual_aid_flag` BOOLEAN COMMENT 'Indicates whether the dispatched crew is a mutual aid crew provided by another utility or contractor under a mutual assistance agreement. Used for storm cost tracking, mutual aid settlement, and NERC EOP-011 compliance reporting.',
    `oms_incident_number` STRING COMMENT 'The incident or trouble call number assigned by the Outage Management System (OMS) that initiated this dispatch. Provides cross-system traceability between the OMS incident record and the dispatch record.',
    `operating_district_code` STRING COMMENT 'Internal operating district or division code for the area where the outage occurred. Used for crew assignment routing, regional performance reporting, and SAIDI/SAIFI district-level aggregation.',
    `safety_clearance_number` STRING COMMENT 'Unique identifier for the safety clearance or hold tag issued to the crew before commencing energized work. Required for OSHA lockout/tagout compliance and NERC CIP physical security documentation.',
    `service_territory_code` STRING COMMENT 'Code identifying the utility service territory or operating district in which the outage site is located. Used for regulatory reporting to State Public Utility Commissions (PUCs) and for regional resource allocation.',
    `site_latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate (decimal degrees, WGS84) of the outage site to which the crew is dispatched. Sourced from GIS or OMS outage location data for field navigation and spatial analytics.',
    `site_longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate (decimal degrees, WGS84) of the outage site to which the crew is dispatched. Sourced from GIS or OMS outage location data for field navigation and spatial analytics.',
    `storm_event_flag` BOOLEAN COMMENT 'Indicates whether this dispatch is associated with a declared storm or major event. When true, the dispatch may be excluded from standard SAIDI/SAIFI calculations per IEEE 1366 major event day (MED) exclusion criteria.',
    `switching_order_number` STRING COMMENT 'Reference number of the switching order issued to the crew for safe isolation and restoration of the affected circuit segment. Links to the switching order management workflow in the ADMS.',
    `updated_at` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the crew dispatch record. Supports change tracking, audit compliance, and incremental data pipeline processing.',
    `vehicle_identifier` STRING COMMENT 'Operational identifier for the assigned vehicle (e.g., fleet unit number, license plate, or radio unit ID) as used by dispatchers for field tracking and resource management.',
    `vehicle_number` BIGINT COMMENT 'Reference to the vehicle assigned to this dispatch from the fleet management system. Links to the asset management domain vehicle master record.',
    `work_completed_at` TIMESTAMP COMMENT 'Timestamp when the crew completed all assigned repair or restoration work at the outage site and confirmed task closure in the OMS. Used for SAIDI/CAIDI calculation and restoration performance reporting.',
    `work_order_number` STRING COMMENT 'Reference to the associated work order in the asset management or ERP system (Ventyx Asset Suite or SAP S/4HANA Plant Maintenance) that governs the repair or restoration task assigned to this crew.',
    `work_start_at` TIMESTAMP COMMENT 'Timestamp when the crew began active repair or restoration work at the outage site. Distinct from arrival time — accounts for safety setup, hazard assessment, and switching order receipt before work commences.',
    CONSTRAINT pk_crew_dispatch PRIMARY KEY(`crew_dispatch_id`)
) COMMENT 'Record of a field crew assignment dispatched to an outage location for investigation, repair, or restoration. Captures dispatched crew identifier, dispatch timestamp, estimated travel time, on-site arrival time, work start and completion times, crew type (line crew, troubleshooter, contractor), vehicle assignment, dispatch priority tier, and dispatch status lifecycle. Links to outage events and restoration actions without duplicating workforce master data owned by the workforce domain.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`restoration_action` (
    `restoration_action_id` BIGINT COMMENT 'Unique surrogate identifier for each discrete restoration action record within the outage management system. Primary key for the restoration_action data product.',
    `control_area_id` BIGINT COMMENT 'Foreign key linking to grid.control_area. Business justification: Restoration actions change load/generation balance within control areas, requiring AGC adjustments and interchange schedule updates. Essential for coordinating distribution restoration with transmissi',
    `der_system_id` BIGINT COMMENT 'Foreign key linking to interconnection.der_system. Business justification: FLISR and manual restoration sequences must account for DER presence on segments (anti-islanding protection, voltage regulation impact, fault current contribution). Restoration logic checks DER status',
    `distribution_substation_id` BIGINT COMMENT 'Identifier of the substation serving the network segment affected by this restoration action. Used for substation-level outage aggregation and reliability reporting.',
    `ems_node_id` BIGINT COMMENT 'Foreign key linking to grid.ems_node. Business justification: Restoration actions target specific EMS network nodes/buses. The EMS node identifies the precise network element being restored in the power flow model. Domain experts expect this link to correlate fi',
    `event_id` BIGINT COMMENT 'Reference to the parent outage event that this restoration action is associated with. Links the discrete action to the broader outage lifecycle managed in the OMS.',
    `feeder_id` BIGINT COMMENT 'Identifier of the distribution feeder circuit on which this restoration action was performed, as defined in the GIS and ADMS network model. Used for feeder-level reliability performance tracking.',
    `registry_id` BIGINT COMMENT 'Foreign key linking to asset.registry. Business justification: Restoration actions document which switching assets (breakers, reclosers, switches) were operated during outage restoration. Field crews log asset operations for post-event analysis, maintenance trigg',
    `outage_switching_order_id` BIGINT COMMENT 'Reference to the switching order that authorized or directed this restoration action, if applicable. Switching orders govern the sequence of switching operations for safe restoration.',
    `poi_specification_id` BIGINT COMMENT 'Foreign key linking to interconnection.poi_specification. Business justification: Restoration actions at DER points of interconnection must reference POI specifications for voltage level, phase configuration, protection relay settings, and proper switching sequence to prevent equip',
    `network_segment_id` BIGINT COMMENT 'Reference to the distribution network segment (feeder section, lateral, or zone) affected by this restoration action. Identifies the portion of the grid being isolated, sectionalized, or re-energized.',
    `scada_point_id` BIGINT COMMENT 'Foreign key linking to grid.scada_point. Business justification: Restoration actions involve SCADA-monitored devices (reclosers, switches). Linking enables real-time status verification, FLISR automation, and coordinated distribution automation with EMS operations.',
    `sectionalizing_device_id` BIGINT COMMENT 'Identifier of the switching device (recloser, sectionalizer, circuit breaker, or fuse) operated to isolate the faulted segment during this action. References the device asset in the GIS or ADMS network model.',
    `storm_event_id` BIGINT COMMENT 'Foreign key linking to outage.storm_event. Business justification: The restoration_action table captures discrete restoration steps during outage events. During storm events, restoration actions are part of coordinated storm response and must be traceable to the stor',
    `weather_input_id` BIGINT COMMENT 'Foreign key linking to forecast.weather_input. Business justification: Restoration crews require real-time and forecasted weather data for safety planning, equipment selection, and estimated time of restoration (ETR) accuracy. Weather conditions directly affect restorati',
    `action_completed_timestamp` TIMESTAMP COMMENT 'Timestamp when the restoration action was confirmed complete and verified by the crew or automated system. Used to calculate action duration and assess restoration efficiency.',
    `action_duration_minutes` DECIMAL(18,2) COMMENT 'Elapsed time in minutes from action initiation (action_timestamp) to action completion (action_completed_timestamp). Used in CAIDI calculations and crew performance benchmarking.',
    `action_notes` STRING COMMENT 'Free-text field for operator or crew notes describing the specific conditions, complications, or observations encountered during this restoration action. Supports post-event analysis and lessons-learned documentation.',
    `action_number` STRING COMMENT 'Externally visible, human-readable identifier for this restoration action as recorded in the OMS or switching order log (e.g., RA-2024-00451). Used by field crews, control room operators, and regulators to reference specific actions.',
    `action_sequence` STRING COMMENT 'Ordinal sequence number of this action within the parent outage events restoration workflow. Enables step-by-step reconstruction of the restoration sequence for post-event analysis and SAIDI/SAIFI/CAIDI reporting.',
    `action_status` STRING COMMENT 'Current lifecycle status of the restoration action. Pending: scheduled but not yet started. In_progress: crew or automation is actively executing. Completed: action successfully finished. Failed: action attempted but unsuccessful. Cancelled: action voided before execution.. Valid values are `pending|in_progress|completed|failed|cancelled`',
    `action_timestamp` TIMESTAMP COMMENT 'The principal real-world timestamp when this restoration action was executed or initiated in the field or by the automated system. Used as the primary event time for SAIDI/SAIFI/CAIDI calculations and restoration timeline analysis.',
    `action_type` STRING COMMENT 'Classification of the type of restoration action performed. Isolation: de-energizes a faulted segment. Sectionalizing: divides a feeder to limit the outage zone. Load transfer: moves load to an alternate feeder. Temporary bypass: restores power via a temporary path. Permanent repair: physical repair restoring normal configuration. FLISR automated: Fault Location Isolation and Service Restoration (FLISR) algorithm-driven action.. Valid values are `isolation|sectionalizing|load_transfer|temporary_bypass|permanent_repair|flisr_automated`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this restoration action record was first created in the OMS or data platform. Supports audit trail and data lineage requirements.',
    `crew_arrival_timestamp` TIMESTAMP COMMENT 'Timestamp when the field crew arrived on-site to begin executing this manual restoration action. Used to calculate crew travel time and on-site restoration duration for workforce performance analytics.',
    `crew_dispatched_timestamp` TIMESTAMP COMMENT 'Timestamp when the field crew was dispatched from the control room or dispatch center to execute this restoration action. Used to measure dispatch-to-arrival interval and overall crew response time.',
    `customer_notification_sent` BOOLEAN COMMENT 'Indicates whether a customer notification (outage alert, ETR update, or restoration confirmation) was sent to affected customers as a result of this restoration action. Supports compliance with state PUC customer communication requirements.',
    `customers_affected_count` STRING COMMENT 'Total number of customer service points that were de-energized or affected by the segment targeted by this action at the time of action execution. Provides context for partial vs. full restoration assessment.',
    `customers_requiring_manual` STRING COMMENT 'Number of customers within the affected segment that could not be restored by FLISR automation and required manual crew dispatch for restoration. Highlights FLISR coverage gaps.',
    `customers_restored_automatically` STRING COMMENT 'Number of customers restored through fully automated Fault Location Isolation and Service Restoration (FLISR) self-healing actions without manual crew intervention. Key metric for FLISR performance analytics.',
    `customers_restored_count` STRING COMMENT 'Number of customer service points restored to power as a direct result of this specific restoration action. Used in SAIDI, SAIFI, and CAIDI index calculations and regulatory reliability reporting.',
    `estimated_restoration_time` TIMESTAMP COMMENT 'Estimated Time to Restore (ETR) for the remaining affected customers at the time this action was recorded. Updated as each restoration action is completed to refine the ETR communicated to customers and regulators.',
    `execution_mode` STRING COMMENT 'Indicates whether the restoration action was executed manually by a field crew or control room operator, fully automated by the FLISR algorithm, or semi-automated (system-initiated but operator-confirmed).. Valid values are `manual|automated|semi_automated`',
    `fault_detected_timestamp` TIMESTAMP COMMENT 'Timestamp when the fault triggering this restoration action was first detected by SCADA, FLISR, or field crew. Distinct from action_timestamp; used to calculate fault-to-isolation and fault-to-restoration intervals.',
    `flisr_algorithm_version` STRING COMMENT 'Version identifier of the Fault Location Isolation and Service Restoration (FLISR) algorithm that executed this automated restoration action. Enables performance benchmarking across algorithm versions and supports software change management.',
    `flisr_isolation_actions_taken` STRING COMMENT 'Number of automated switching operations performed by the FLISR algorithm to isolate the faulted segment during this restoration action. Supports FLISR performance analytics and switching operation audits.',
    `flisr_load_transfer_actions_taken` STRING COMMENT 'Number of automated load transfer switching operations performed by the FLISR algorithm to restore power to non-faulted segments during this action. Key metric for FLISR self-healing effectiveness.',
    `flisr_outcome` STRING COMMENT 'Outcome of the FLISR automated restoration attempt for this action. Success: FLISR fully restored the affected segment. Partial_success: FLISR restored a portion; manual intervention required for remainder. Failure: FLISR could not restore; full manual restoration required. Not_applicable: action was manual, not FLISR-driven.. Valid values are `success|partial_success|failure|not_applicable`',
    `is_major_event_day` BOOLEAN COMMENT 'Indicates whether this restoration action occurred during a Major Event Day (MED) as defined by IEEE 1366 beta method. MED events are typically excluded from standard SAIDI/SAIFI calculations and reported separately to regulators.',
    `is_partial_restoration` BOOLEAN COMMENT 'Indicates whether this action resulted in a partial restoration (True) — restoring power to a subset of affected customers — or a full restoration of the affected segment (False). Drives ETR refinement and customer notification logic.',
    `is_planned_outage` BOOLEAN COMMENT 'Indicates whether this restoration action is associated with a planned maintenance outage (True) or an unplanned/forced outage (False). Planned outages are tracked separately for SAIDI/SAIFI reporting and customer notification compliance.',
    `load_transfer_source_feeder` STRING COMMENT 'Identifier of the source feeder or substation bus from which load is transferred during a load transfer restoration action. Populated when action_type is load_transfer or flisr_automated.',
    `load_transfer_target_feeder` STRING COMMENT 'Identifier of the target feeder or substation bus receiving the transferred load during a load transfer restoration action. Used to assess feeder loading and capacity constraints post-transfer.',
    `oms_action_reference` STRING COMMENT 'Source system reference key for this restoration action as recorded in the GE PowerOn ADMS Outage Management System (OMS). Enables traceability and reconciliation between the lakehouse silver layer and the operational OMS.',
    `outage_cause_code` STRING COMMENT 'Standardized cause code for the fault or outage condition that necessitated this restoration action (e.g., equipment failure, tree contact, animal contact, storm, vehicle accident, planned maintenance). Aligns with IEEE 1366 cause code taxonomy. [ENUM-REF-CANDIDATE: equipment_failure|tree_contact|animal_contact|storm|vehicle_accident|planned_maintenance|unknown|other — promote to reference product]',
    `regulatory_reportable` BOOLEAN COMMENT 'Indicates whether this restoration action is associated with an outage event that must be reported to a regulatory body (NERC, FERC, State PUC, or DOE). Drives inclusion in regulatory reliability reports and OE-417 emergency incident filings.',
    `scada_event_reference` STRING COMMENT 'Reference identifier linking this restoration action to the corresponding SCADA (Supervisory Control and Data Acquisition) event or alarm in OSIsoft PI historian. Enables correlation between OMS restoration records and real-time grid telemetry.',
    `to_crew` BIGINT COMMENT 'FK to outage.crew_dispatch.crew_dispatch_id — Each restoration action is performed by a dispatched crew. Links action to the crew that executed it for accountability and performance tracking.',
    `to_crew_dispatch` BIGINT COMMENT 'FK to outage.crew_dispatch.crew_dispatch_id — Restoration actions are performed by dispatched crews. This FK links the action to the crew that executed it, enabling crew performance tracking and accountability.',
    `to_outage_event` BIGINT COMMENT 'FK to outage.outage_event.outage_event_id — Every restoration action is performed within the context of an outage event. Required for step-by-step restoration tracking and ETR refinement.',
    `transferred_load_mw` DECIMAL(18,2) COMMENT 'Magnitude of electrical load in Megawatts (MW) transferred from the faulted segment to an alternate feeder during a load transfer action. Used for grid capacity analysis and post-event load flow validation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this restoration action record was last modified. Tracks updates to status, customer counts, or FLISR outcome fields throughout the restoration lifecycle.',
    `voltage_level_kv` DECIMAL(18,2) COMMENT 'Nominal voltage level in kilovolts (kV) of the network segment on which this restoration action was performed (e.g., 4.16, 12.47, 34.5, 69, 115 kV). Used to classify the action within transmission vs. distribution tiers.',
    CONSTRAINT pk_restoration_action PRIMARY KEY(`restoration_action_id`)
) COMMENT 'Discrete restoration action taken during an outage event to restore power to a portion of affected customers, covering both manual and automated (FLISR) restoration. Records action type (isolation, sectionalizing, temporary bypass, permanent repair, load transfer, automated FLISR), execution mode (manual crew action vs automated grid self-healing), affected segment, customers restored by this action, action timestamp, crew performing the action (if manual), partial vs. full restoration flag, FLISR-specific attributes (fault detection timestamp, faulted segment, isolation actions taken automatically, load transfer actions, FLISR algorithm version, success/failure outcome, customers restored automatically vs requiring manual intervention). Enables step-by-step restoration tracking, ETR refinement, and FLISR performance analytics.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`cause` (
    `cause_id` BIGINT COMMENT 'Unique surrogate identifier for each outage cause code record in the reference classification table. Primary key. [REFERENCE_LOOKUP role — canonical_skip_reason: This entity is a reference/lookup table of cause codes; per-role minimum categories do not apply.]',
    `asset_class_applicability` STRING COMMENT 'Identifies the class(es) of utility assets to which this cause code applies (e.g., Overhead Distribution, Underground Transmission, Substation Equipment, Generation Unit). Supports asset-cause correlation in reliability and asset management analytics.',
    `cause_category` STRING COMMENT 'High-level grouping of the outage cause into standard industry categories. Drives SAIDI/SAIFI/CAIDI segmentation in reliability analytics and PUC regulatory reporting. [ENUM-REF-CANDIDATE: equipment_failure|weather|vegetation|animal_contact|human_error|third_party_damage|unknown — promote to reference product]',
    `cause_code` STRING COMMENT 'Alphanumeric code uniquely identifying the outage cause within the classification system. Used as the business-facing key in OMS, regulatory filings, and reliability reports. Sourced from GE PowerOn ADMS cause code configuration.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `cause_description` STRING COMMENT 'Full narrative description of the outage cause, including typical failure modes, contributing conditions, and examples. Used for training, documentation, and regulatory submissions.',
    `cause_group` STRING COMMENT 'Operational grouping of cause codes for internal reporting and benchmarking purposes (e.g., Overhead T&D, Underground T&D, Substation, Generation, External). Supports drill-down analysis in reliability dashboards.',
    `cause_name` STRING COMMENT 'Human-readable short name for the outage cause (e.g., Tree Contact, Equipment Failure - Transformer, Animal Contact). Displayed in OMS dashboards and regulatory reports.',
    `cause_status` STRING COMMENT 'Current lifecycle status of the cause code record. Active codes are available for OMS event classification; deprecated codes are retained for historical reporting only; pending_review codes are under regulatory or operational review.. Valid values are `active|inactive|deprecated|pending_review`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this cause code record was first created in the data platform. Supports data lineage, audit trail, and change management for the reference classification table.',
    `crew_type_required` STRING COMMENT 'Identifies the type of field crew typically required to restore outages of this cause (e.g., Line Crew, Cable Crew, Substation Technician, Tree Crew, Damage Assessment). Supports automated crew dispatch recommendations in OMS.',
    `customer_notification_required` BOOLEAN COMMENT 'Indicates whether outages with this cause trigger mandatory proactive customer notification obligations (e.g., via IVR, SMS, or email). Supports compliance with PUC customer communication requirements.',
    `effective_date` DATE COMMENT 'The date from which this cause code is valid and available for use in outage event classification. Supports temporal versioning of the cause code reference table for historical reporting accuracy.',
    `epa_cause_indicator` STRING COMMENT 'Indicates whether the outage cause has environmental reporting implications under EPA regulations (e.g., spill events, emissions exceedances triggered by unplanned generation outages). Used for environmental compliance tracking.',
    `expiry_date` DATE COMMENT 'The date after which this cause code is no longer valid for new outage event classification. Null indicates the code is currently active with no planned expiry. Supports cause code lifecycle management and historical data integrity.',
    `ieee_1366_category` STRING COMMENT 'Classification of the outage cause under IEEE Standard 1366 for electric power distribution reliability indices. Determines how interruptions associated with this cause are counted in SAIDI, SAIFI, and CAIDI calculations.. Valid values are `sustained|momentary|major_event_day|planned|unknown`',
    `insurance_claimable` BOOLEAN COMMENT 'Indicates whether outage events attributed to this cause are eligible for insurance claim submission (e.g., storm damage, third-party damage). Supports financial recovery tracking and CAPEX/OPEX classification.',
    `is_controllable` BOOLEAN COMMENT 'Indicates whether the outage cause is considered controllable by the utility (i.e., preventable through operational or maintenance actions). Used in reliability improvement program targeting and PUC performance benchmarking.',
    `is_doe_reportable` BOOLEAN COMMENT 'Indicates whether outage events with this cause require submission to the U.S. Department of Energy via the OE-417 Electric Emergency Incident and Disturbance Report. True = DOE OE-417 filing required.',
    `is_med_exclusion` BOOLEAN COMMENT 'Indicates whether outage events attributed to this cause qualify for exclusion from SAIDI/SAIFI/CAIDI baseline calculations as a Major Event Day (MED) under IEEE 1366. True = MED-eligible exclusion; False = included in standard reliability indices.',
    `is_momentary` BOOLEAN COMMENT 'Indicates whether this cause code is associated with momentary interruptions (duration less than 5 minutes per IEEE 1366). Momentary events are tracked separately in MAIFI (Momentary Average Interruption Frequency Index) calculations.',
    `is_nerc_reportable` BOOLEAN COMMENT 'Indicates whether outage events attributed to this cause trigger mandatory NERC event reporting obligations (e.g., EOP-004 threshold events). True = NERC reporting required; False = not required.',
    `is_planned` BOOLEAN COMMENT 'Indicates whether this cause code applies to planned (scheduled) outages rather than unplanned interruptions. Planned outages are excluded from SAIDI/SAIFI/CAIDI calculations per IEEE 1366. True = planned; False = unplanned.',
    `is_puc_reportable` BOOLEAN COMMENT 'Indicates whether outage events with this cause must be reported to the state Public Utility Commission (PUC) under applicable regulatory reporting requirements. True = mandatory PUC notification required; False = not required.',
    `is_weather_related` BOOLEAN COMMENT 'Indicates whether the outage cause is classified as weather-related. Drives storm response analytics, MED determination, and insurance/force-majeure reporting. Distinct from the cause_category field as some sub-causes may be weather-adjacent.',
    `nerc_cause_category` STRING COMMENT 'NERC-defined top-level cause category label corresponding to the nerc_cause_code. Supports direct mapping to NERC event reporting taxonomy without requiring a separate lookup. Examples: Electrical, Environmental, Human Error, Other.',
    `nerc_cause_code` STRING COMMENT 'Standardized cause code as defined by NERC for transmission and bulk electric system outage reporting. Required for NERC event reporting (EOP-004) and DOE OE-417 submissions. Maps the internal cause code to the NERC taxonomy.. Valid values are `^[A-Z0-9]{1,10}$`',
    `oms_cause_code` STRING COMMENT 'The native cause code identifier as configured in the GE PowerOn ADMS/OMS system. Used for direct system integration, data lineage tracing, and reconciliation between the silver layer and the source OMS.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `puc_cause_code` STRING COMMENT 'The cause code as defined in the applicable state Public Utility Commission (PUC) reporting taxonomy. Required for annual reliability reports and service quality filings. May differ from internal cause_code.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `regulatory_reporting_notes` STRING COMMENT 'Free-text field capturing specific regulatory reporting instructions, exceptions, or conditions associated with this cause code. Used by compliance teams to document PUC, NERC, or DOE reporting nuances for this cause.',
    `reliability_index_impact` STRING COMMENT 'Identifies which reliability performance indices (SAIDI, SAIFI, CAIDI, MAIFI) are impacted by outage events attributed to this cause. Drives automated index calculation logic in the reliability analytics platform.. Valid values are `saidi|saifi|caidi|maifi|all|none`',
    `saidi_weight_factor` DECIMAL(18,2) COMMENT 'Numeric weighting factor applied to SAIDI calculations for outages of this cause type. Allows regulatory-mandated cause-specific weighting adjustments in reliability index computations. Default is 1.0 (no adjustment).',
    `sort_order` STRING COMMENT 'Numeric value controlling the display sequence of cause codes in OMS dropdown lists, regulatory report templates, and analytics dashboards. Lower values appear first.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this cause code was sourced or synchronized (e.g., GE PowerOn ADMS, SAP IS-U). Supports data lineage and reconciliation in the Databricks silver layer.. Valid values are `GE_PowerOn_ADMS|SAP_ISU|Oracle_CCB|Manual|Other`',
    `sub_cause_code` STRING COMMENT 'Secondary classification code providing finer granularity within a cause category (e.g., within equipment_failure: transformer, cable, switch, fuse). Enables detailed root-cause analysis and asset failure trending.. Valid values are `^[A-Z0-9_]{2,30}$`',
    `sub_cause_name` STRING COMMENT 'Human-readable label for the sub-cause code (e.g., Overhead Conductor, Underground Cable Fault, Fuse Operation). Used in OMS event classification and crew dispatch workflows.',
    `switching_order_required` BOOLEAN COMMENT 'Indicates whether outages attributed to this cause typically require a formal switching order to be issued before restoration work can begin. Drives workflow automation in OMS switching order management.',
    `third_party_liability_flag` BOOLEAN COMMENT 'Indicates whether outages attributed to this cause may involve third-party liability (e.g., contractor damage, vehicle contact, excavation damage). Triggers claims management and legal notification workflows.',
    `typical_duration_minutes` STRING COMMENT 'Historical average or benchmark restoration duration in minutes for outages attributed to this cause. Used for crew dispatch planning, customer estimated restoration time (ERT) communications, and CAIDI benchmarking.',
    `typical_restoration_priority` STRING COMMENT 'Default restoration priority level associated with outages of this cause type. Used to pre-populate restoration prioritization workflows in OMS and crew dispatch systems. Overridable at the individual outage event level.. Valid values are `critical|high|medium|low`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this cause code record. Used for incremental data pipeline processing, change detection, and audit compliance.',
    `version_number` STRING COMMENT 'Incremental version number tracking revisions to the cause code definition, category mapping, or regulatory alignment. Supports audit trail and change management for the reference classification table.',
    `voltage_level_applicability` STRING COMMENT 'Indicates the voltage level(s) at which this cause code is applicable: transmission (>= 115 kV), sub-transmission, distribution (< 35 kV), or all levels. Ensures correct cause code assignment during OMS event classification.. Valid values are `transmission|sub_transmission|distribution|all`',
    CONSTRAINT pk_cause PRIMARY KEY(`cause_id`)
) COMMENT 'Reference classification of outage cause codes used to categorize the root cause of interruption events. Includes cause category (equipment failure, weather, vegetation, animal contact, human error, third-party damage, unknown), sub-cause code, NERC cause code mapping, PUC reportable flag, and whether the cause qualifies as a Major Event Day (MED) exclusion under IEEE 1366. Drives regulatory reporting and reliability analytics.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`planned_outage_window` (
    `planned_outage_window_id` BIGINT COMMENT 'Primary key for planned_outage_window',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to interconnection.interconnection_agreement. Business justification: Planned outages affecting DER customers require notification per interconnection agreement advance notice terms and may trigger mandatory export curtailment or disconnection per agreement operating re',
    `cause_id` BIGINT COMMENT 'Foreign key linking to outage.cause. Business justification: The planned_outage_window table has outage_cause_code (STRING) as a denormalized cause reference. The cause table is the authoritative reference for outage cause classifications including planned outa',
    `contingency_analysis_run_id` BIGINT COMMENT 'Foreign key linking to grid.contingency_analysis_run. Business justification: Planned outage windows require a contingency analysis run to verify N-1 compliance before approval. NERC TPL standards mandate contingency analysis for planned outages. Domain experts expect this link',
    `distribution_substation_id` BIGINT COMMENT 'Identifier of the substation from which the affected feeder or circuit originates. Used for switching coordination, crew dispatch, and geographic impact analysis.',
    `feeder_id` BIGINT COMMENT 'Identifier of the primary distribution feeder or circuit segment to be de-energized during the planned outage window. Sourced from the GIS network model (Esri ArcGIS Utility Network) and used for switching order generation.',
    `load_id` BIGINT COMMENT 'Foreign key linking to forecast.load. Business justification: Planned outage scheduling requires load forecasts to minimize customer impact by avoiding high-demand periods. Distribution operations centers use hourly load forecasts to schedule maintenance during ',
    `registry_id` BIGINT COMMENT 'Foreign key linking to asset.registry. Business justification: Planned outages are scheduled to perform work on specific assets (transformers, circuit breakers, transmission lines). Outage coordination requires knowing which asset is being maintained for customer',
    `weather_input_id` BIGINT COMMENT 'Foreign key linking to forecast.weather_input. Business justification: Planned outage scheduling depends on weather forecasts to avoid adverse conditions that could extend outage duration or compromise crew safety. Utilities routinely reschedule planned work based on for',
    `actual_duration_minutes` STRING COMMENT 'Actual duration of the de-energization in minutes, recorded upon restoration. Used to compute duration variance against planned_duration_minutes and to feed SAIDI/SAIFI/CAIDI reliability indices.',
    `actual_end_timestamp` TIMESTAMP COMMENT 'Actual date and time at which the network segment was re-energized and service restored. Used to compute actual outage duration and variance against planned duration for SAIDI/SAIFI/CAIDI performance reporting.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Actual date and time at which the network segment was de-energized. Compared against planned_start_timestamp to compute schedule variance for reliability reporting and SAIDI/SAIFI tracking.',
    `advance_notice_period_hours` STRING COMMENT 'Minimum advance notice period in hours required before the planned outage commences, as mandated by state PUC tariff rules or internal SLA policy. Drives the customer notification scheduling workflow.',
    `affected_customer_count` STRING COMMENT 'Estimated number of customer service points (meters) that will experience interruption during the planned outage window. Used for customer notification prioritization, regulatory reporting, and SAIFI impact assessment.',
    `alternate_feed_available` BOOLEAN COMMENT 'Indicates whether an alternate supply path exists to maintain service to some or all affected customers during the planned outage window. Informs restoration strategy and customer notification messaging.',
    `approval_status` STRING COMMENT 'Approval workflow status for the planned outage window, tracking whether the request has been reviewed and authorized by the appropriate operations or grid control authority before execution.. Valid values are `pending|approved|rejected|withdrawn`',
    `approved_by` STRING COMMENT 'Identifier or name of the operations supervisor, grid control authority, or system operator who authorized the planned outage window. Required for audit trail and NERC compliance documentation.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time at which the planned outage window received formal authorization from the approving authority. Part of the approval audit trail required for NERC and PUC compliance.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time at which the planned outage window record was first created in the system. Used for audit trail, workflow SLA tracking, and advance notice compliance verification.',
    `critical_customer_count` STRING COMMENT 'Number of critical or life-support customers (medical baseline, hospitals, emergency services) within the affected area. Drives mandatory advance notification requirements and restoration prioritization per PUC rules.',
    `customer_notification_required` BOOLEAN COMMENT 'Indicates whether customer advance notification is required for this planned outage window based on PUC tariff rules, affected customer count thresholds, or presence of critical customers.',
    `customer_notification_sent` BOOLEAN COMMENT 'Indicates whether the required customer advance notification has been dispatched for this planned outage window. Used for compliance tracking and audit trail against PUC notification obligations.',
    `duration_variance_minutes` STRING COMMENT 'Difference between actual and planned outage duration in minutes (actual_duration_minutes minus planned_duration_minutes). Positive values indicate overrun; negative values indicate early restoration. Key metric for reliability performance reporting.',
    `estimated_load_mw` DECIMAL(18,2) COMMENT 'Estimated peak load in megawatts (MW) that will be interrupted during the planned outage window. Used for grid stability assessment, load transfer planning, and RTO/ISO notification thresholds.',
    `geographic_region` STRING COMMENT 'Geographic region or district within the service territory where the planned outage is located (e.g., North District, Urban Core, Rural East). Used for crew dispatch routing and regional reliability reporting.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time at which the planned outage window record was most recently modified. Used for change tracking, data lineage, and Silver layer incremental processing.',
    `load_transfer_required` BOOLEAN COMMENT 'Indicates whether load transfer switching is required to maintain service to customers via alternate feed paths during the planned outage window. Triggers switching order generation and crew coordination.',
    `notification_channel` STRING COMMENT 'Primary channel used to deliver the planned outage advance notification to affected customers (e.g., IVR automated call, SMS, email, postal mail, online portal, or field visit for critical customers).. Valid values are `ivr|sms|email|mail|portal|field_visit`',
    `notification_sent_timestamp` TIMESTAMP COMMENT 'Date and time at which the customer advance notification was dispatched. Used to verify compliance with the required advance_notice_period_hours and to support PUC audit inquiries.',
    `outage_reference_number` STRING COMMENT 'Externally-known business identifier for the planned outage window, used in customer notifications, regulatory filings, and OMS records. Format: POW-{YYYY}-{NNNNNN}.. Valid values are `^POW-[0-9]{4}-[0-9]{6}$`',
    `outage_window_status` STRING COMMENT 'Current lifecycle state of the planned outage window through its approval and execution workflow. Tracks progression from initial draft through approval, active execution, and final completion or cancellation.. Valid values are `draft|pending_approval|approved|in_progress|completed|cancelled`',
    `outage_window_type` STRING COMMENT 'Classification of the planned outage window by the nature of the work activity requiring de-energization. Drives notification requirements, crew dispatch, and regulatory filing obligations. [ENUM-REF-CANDIDATE: maintenance|construction|upgrade|inspection|testing|emergency_planned|commissioning|decommissioning — promote to reference product]. Valid values are `maintenance|construction|upgrade|inspection|testing|emergency_planned`',
    `planned_duration_minutes` STRING COMMENT 'Planned duration of the de-energization window in minutes, derived from planned start and end timestamps at scheduling time. Stored explicitly for scheduling, crew planning, and customer notification purposes.',
    `planned_end_timestamp` TIMESTAMP COMMENT 'Scheduled date and time at which the network segment is planned to be re-energized and service restored. Used to calculate planned outage duration and customer notification windows.',
    `planned_start_timestamp` TIMESTAMP COMMENT 'Scheduled date and time at which the network segment is planned to be de-energized to begin the maintenance or construction activity. Used for customer advance notification and crew scheduling.',
    `regulatory_filing_reference` STRING COMMENT 'Reference number or docket number of the regulatory filing submitted to the PUC, NERC, or FERC for this planned outage. Populated only when regulatory_filing_required is true.',
    `regulatory_filing_required` BOOLEAN COMMENT 'Indicates whether this planned outage window requires a formal regulatory filing with the state PUC, NERC, or FERC prior to execution (e.g., for high-voltage transmission outages or outages affecting critical infrastructure).',
    `requested_by` STRING COMMENT 'Identifier or name of the employee, crew supervisor, or project manager who submitted the planned outage window request. Used for accountability tracking and workflow routing.',
    `requesting_department` STRING COMMENT 'Name or code of the business unit or department (e.g., T&D Engineering, Asset Management, Construction) that initiated the planned outage window request. Used for resource allocation and OPEX/CAPEX tracking.',
    `rto_iso_notification_required` BOOLEAN COMMENT 'Indicates whether the planned outage must be reported to the Regional Transmission Organization (RTO) or Independent System Operator (ISO) due to transmission-level impact or market implications under NERC/FERC requirements.',
    `rto_iso_outage_code` STRING COMMENT 'Outage coordination identifier assigned by the RTO or ISO (e.g., MISO, PJM, CAISO) when the planned outage is registered in the transmission outage coordination system. Populated only when rto_iso_notification_required is true.',
    `saidi_contribution_minutes` DECIMAL(18,2) COMMENT 'Contribution of this planned outage window to the annual System Average Interruption Duration Index (SAIDI) in customer-minutes per customer served. Calculated as (actual_duration_minutes × affected_customer_count) / total_customers_served. Used for IEEE 1366 reliability reporting.',
    `saifi_contribution` DECIMAL(18,2) COMMENT 'Contribution of this planned outage window to the annual System Average Interruption Frequency Index (SAIFI), calculated as affected_customer_count / total_customers_served. Used for IEEE 1366 reliability performance reporting to PUC.',
    `service_territory_code` STRING COMMENT 'Code identifying the regulated service territory within which the planned outage window occurs. Used for PUC jurisdictional reporting, rate case filings, and geographic performance analysis.',
    `storm_event_flag` BOOLEAN COMMENT 'Indicates whether this planned outage window is associated with a declared storm or major event, which may qualify for IEEE 1366 major event day (MED) exclusion from SAIDI/SAIFI reliability index calculations.',
    `switching_order_number` STRING COMMENT 'Reference number of the switching order issued in the ADMS or OMS to execute the de-energization and re-energization sequence for this planned outage window. Links to the operational switching workflow.',
    `voltage_level_kv` DECIMAL(18,2) COMMENT 'Nominal operating voltage level in kilovolts (kV) of the network segment being de-energized. Determines safety protocols, crew qualifications, and regulatory notification thresholds.',
    `work_description` STRING COMMENT 'Free-text description of the maintenance, construction, or upgrade activity to be performed during the planned outage window. Provides context for crew briefings, customer communications, and regulatory filings.',
    `work_order_number` STRING COMMENT 'Reference number of the associated work order in the asset management or ERP system (e.g., SAP S/4HANA PM or Ventyx Asset Suite) that drives the maintenance, construction, or upgrade activity requiring de-energization.',
    CONSTRAINT pk_planned_outage_window PRIMARY KEY(`planned_outage_window_id`)
) COMMENT 'Scheduled planned outage window for maintenance, construction, or upgrade activities requiring deliberate de-energization of network segments. Captures planned start and end times, affected feeder/circuit, work order reference, customer notification requirement, advance notice period, regulatory filing requirement, and actual vs. planned duration variance. Distinct from unplanned outage events — has its own approval and notification workflow.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`affected_customer` (
    `affected_customer_id` BIGINT COMMENT 'Unique surrogate identifier for the affected customer association record linking a customer service point to an outage or planned maintenance event.',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to interconnection.interconnection_agreement. Business justification: Customer interruption records for DER customers must reference interconnection agreements for regulatory reporting of DER availability, NEM credit calculations during outages, and compliance with PUC ',
    `billing_service_agreement_id` BIGINT COMMENT 'Foreign key linking to billing.billing_service_agreement. Business justification: Affected customer records need service agreement link to determine applicable credit/adjustment rules, verify eligibility for outage compensation programs, and ensure credits are posted to correct bil',
    `crew_dispatch_id` BIGINT COMMENT 'Reference to the crew dispatch or work order assigned to restore power at this customer service point. Links to the field crew assignment in the OMS or Work Management System.',
    `account_id` BIGINT COMMENT 'Reference to the customer account record in the Customer Information System (CIS). Sourced from SAP IS-U or Oracle CC&B customer account master.',
    `der_system_id` BIGINT COMMENT 'Foreign key linking to interconnection.der_system. Business justification: Tracks DER-owning customers experiencing outages for NEM credit adjustments (energy not exported during outage), performance guarantee calculations, and regulatory reporting (CPUC Rule 21 requires tra',
    `distribution_substation_id` BIGINT COMMENT 'Identifier of the substation serving this customer service point at the time of the outage. Used for substation-level reliability performance reporting and asset management correlation.',
    `event_id` BIGINT COMMENT 'Reference to the parent outage or planned maintenance event that caused this customer interruption. Links to the outage event record in the Outage Management System (OMS).',
    `feeder_id` BIGINT COMMENT 'Identifier of the distribution feeder circuit serving this customer service point at the time of the outage. Used for feeder-level reliability analysis and SAIDI/SAIFI segmentation.',
    `interruption_id` BIGINT COMMENT 'Foreign key linking to outage.interruption. Business justification: The affected_customer table and interruption table both track customer-level outage impacts but are not directly linked. The interruption table captures granular premise-level interruption records (du',
    `meter_id` BIGINT COMMENT 'Reference to the meter installed at the affected service point. Used to correlate outage impact with Advanced Metering Infrastructure (AMI) last-gasp signals and meter data.',
    `outage_switching_order_id` BIGINT COMMENT 'Reference to the switching order or planned maintenance work order that caused this customer interruption. Populated for planned outages; null for unplanned events.',
    `planned_outage_window_id` BIGINT COMMENT 'Foreign key linking to outage.planned_outage_window. Business justification: The affected_customer table links customers to outage events but has no direct FK to planned_outage_window. For planned outages, customers are notified in advance and their interruption records are tr',
    `premise_id` BIGINT COMMENT 'Foreign key linking to customer.premise. Business justification: Affected customer records must be tied to specific service premises for premise-level SAIDI/SAIFI calculations, life support flag verification, and premise-based restoration prioritization. affected_c',
    `service_point_id` BIGINT COMMENT 'Reference to the specific service point (premise delivery point) associated with this customer interruption. Corresponds to the service point or premise identifier in the CIS and GIS.',
    `storm_event_id` BIGINT COMMENT 'Foreign key linking to outage.storm_event. Business justification: The affected_customer table has storm_event_flag (BOOLEAN) indicating the customer was affected during a storm, but no FK to the storm_event master record. Direct linkage to storm_event enables storm-',
    `call_id` BIGINT COMMENT 'Reference identifier for the customer trouble call or service request that reported this outage, as recorded in the Customer Information System (CIS) or CRM. Populated when customer_reported_flag is True.',
    `account_number` STRING COMMENT 'The externally-known customer account number as assigned by the Customer Information System (CIS). Used for customer-facing communications and regulatory impact reporting.',
    `advance_notice_hours` DECIMAL(18,2) COMMENT 'Number of hours of advance notice provided to this customer prior to a planned interruption. Used to verify compliance with PUC minimum advance notification requirements for planned outages (typically 48–72 hours).',
    `cause_code` STRING COMMENT 'Standardized cause code classifying the root cause of the outage affecting this customer (e.g., equipment failure, tree contact, animal contact, weather, vehicle accident). Sourced from OMS cause code taxonomy aligned with EEI/NERC reporting categories. [ENUM-REF-CANDIDATE: equipment_failure|tree_contact|animal_contact|weather|vehicle_accident|scheduled_maintenance|unknown|other — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this affected customer association record was first created in the system, typically when the outage event was declared and customer impact was identified by the OMS.',
    `critical_care_flag` BOOLEAN COMMENT 'Indicates whether the customer at this service point is registered as a critical care or life support customer (e.g., medical baseline, home oxygen, dialysis). Critical care customers receive priority restoration and mandatory advance notification per PUC regulations.',
    `critical_care_type` STRING COMMENT 'Specific type of critical care or life support designation for the affected customer. Populated only when critical_care_flag is True. Classified as restricted health information per HIPAA and state PUC medical baseline program rules.. Valid values are `medical_baseline|life_support|home_oxygen|dialysis|other`',
    `customer_class` STRING COMMENT 'Regulatory and rate classification of the customer affected by the outage. Used for segmented reliability reporting and prioritization of restoration efforts per PUC requirements.. Valid values are `residential|commercial|industrial|agricultural|municipal`',
    `customer_reported_flag` BOOLEAN COMMENT 'Indicates whether this outage was identified through a customer trouble call or self-reported via web/app, as opposed to being detected automatically via AMI last-gasp, SCADA, or OMS prediction. Used for outage detection source analysis.',
    `data_source_system` STRING COMMENT 'Identifies the operational source system from which this affected customer record was ingested into the Silver Layer lakehouse. Used for data lineage, reconciliation, and audit purposes.. Valid values are `GE_PowerOn_ADMS|SAP_ISU|Oracle_CCB|Oracle_MDM|ArcGIS|manual`',
    `der_customer_flag` BOOLEAN COMMENT 'Indicates whether the affected customer has a registered Distributed Energy Resource (DER) such as rooftop solar, battery storage, or a Net Energy Metering (NEM) arrangement. Relevant for assessing behind-the-meter (BTM) resilience and grid impact during outages.',
    `estimated_restoration_timestamp` TIMESTAMP COMMENT 'The estimated date and time of power restoration communicated to this customer. Corresponds to the Estimated Restoration Time (ERT) published in customer-facing outage communications and OMS crew dispatch workflows.',
    `interruption_duration_minutes` STRING COMMENT 'Total duration of the power interruption at this customer service point in minutes, calculated from interruption start to end timestamp. Used directly in SAIDI (System Average Interruption Duration Index) and CAIDI (Customer Average Interruption Duration Index) regulatory reporting.',
    `interruption_end_timestamp` TIMESTAMP COMMENT 'The date and time when power supply was restored at this customer service point. Null if restoration has not yet occurred. Used in SAIDI/CAIDI duration calculations.',
    `interruption_start_timestamp` TIMESTAMP COMMENT 'The date and time when power supply was interrupted at this customer service point. Used as the principal business event timestamp for SAIDI/SAIFI/CAIDI reliability index calculations and regulatory reporting.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this affected customer association record was most recently modified, such as when restoration status was updated, notification was sent, or duration was recalculated.',
    `major_event_flag` BOOLEAN COMMENT 'Indicates whether this customer interruption is associated with a declared Major Event Day (MED) per IEEE 1366 criteria. Major event interruptions are excluded from standard SAIDI/SAIFI calculations and reported separately to regulators.',
    `momentary_flag` BOOLEAN COMMENT 'Indicates whether this interruption is classified as a momentary interruption (duration under 5 minutes per IEEE 1366 definition). Momentary interruptions are counted in MAIFI (Momentary Average Interruption Frequency Index) rather than SAIDI/SAIFI.',
    `notification_channel` STRING COMMENT 'The communication channel used to deliver the outage notification to this customer (e.g., SMS text, email, Interactive Voice Response (IVR) call, mobile app push notification). Supports multi-channel outage communication tracking.. Valid values are `sms|email|ivr|app_push|none`',
    `notification_sent_flag` BOOLEAN COMMENT 'Indicates whether an outage notification has been sent to this customer for the associated outage event. Used to track compliance with PUC customer notification requirements.',
    `notification_timestamp` TIMESTAMP COMMENT 'The date and time when the outage notification was sent to this customer. Used for regulatory compliance reporting on customer notification timeliness.',
    `oms_customer_ref` STRING COMMENT 'External customer reference identifier as recorded in the Outage Management System (OMS), used for cross-system reconciliation between OMS and CIS records.',
    `outage_type` STRING COMMENT 'Classification of the outage event type affecting this customer. unplanned = unexpected fault-driven interruption, planned = scheduled maintenance window, momentary = interruption under 5 minutes per IEEE 1366, major_event = declared major event excluded from standard reliability indices.. Valid values are `unplanned|planned|momentary|major_event`',
    `planned_interruption_end_timestamp` TIMESTAMP COMMENT 'The originally scheduled end time of the planned maintenance interruption for this customer service point. Populated only for planned outages. Compared against actual interruption_end_timestamp for schedule adherence reporting.',
    `planned_interruption_start_timestamp` TIMESTAMP COMMENT 'The originally scheduled start time of the planned maintenance interruption for this customer service point. Populated only for planned outages. Compared against actual interruption_start_timestamp for schedule adherence reporting.',
    `regulatory_exclusion_reason` STRING COMMENT 'Reason code indicating why this customer interruption is excluded from standard IEEE 1366 reliability index calculations. major_event = IEEE 1366 MED exclusion, planned = scheduled maintenance exclusion, momentary = under 5-minute threshold, none = included in standard indices.. Valid values are `major_event|planned|momentary|none`',
    `restoration_confirmation_method` STRING COMMENT 'The method by which power restoration was confirmed at this customer service point. ami_signal = AMI meter power-on event, crew_verification = field crew confirmation, customer_callback = customer reported power restored, scada = SCADA system indication.. Valid values are `ami_signal|crew_verification|customer_callback|scada|none`',
    `restoration_confirmed_flag` BOOLEAN COMMENT 'Indicates whether power restoration at this customer service point has been confirmed, either via AMI last-gasp/power-on signal, crew field verification, or customer callback. Distinguishes crew-reported restoration from confirmed restoration.',
    `restoration_status` STRING COMMENT 'Current restoration lifecycle status for this customer service point. interrupted = power out, restored = power confirmed back, partial = partial restoration, pending_confirmation = crew reports restored but not yet confirmed, excluded = excluded from reliability indices per IEEE 1366 major event criteria.. Valid values are `interrupted|restored|partial|pending_confirmation|excluded`',
    `saidi_contribution_minutes` DECIMAL(18,2) COMMENT 'This customers individual contribution to the SAIDI reliability index in customer-minutes. Equals the interruption duration in minutes for this customer record. Aggregated across all affected customers to compute system-level SAIDI per IEEE 1366.',
    `saifi_contribution` DECIMAL(18,2) COMMENT 'This customers individual contribution to the SAIFI reliability index (value of 1 per sustained interruption, 0 for momentary). Aggregated across all affected customers to compute system-level SAIFI per IEEE 1366.',
    `service_territory_code` STRING COMMENT 'Code identifying the regulated service territory in which this customer service point is located. Used for jurisdictional reliability reporting to the applicable State Public Utility Commission (PUC).',
    `storm_event_flag` BOOLEAN COMMENT 'Indicates whether this customer interruption occurred during a declared storm or major weather event. Used for storm response performance reporting and potential major event day exclusion analysis.',
    CONSTRAINT pk_affected_customer PRIMARY KEY(`affected_customer_id`)
) COMMENT 'Association record linking a specific customer service point to an outage event or planned maintenance window, capturing the customer-level impact. Records customer account reference, service point identifier, interruption start and end times, duration, notification sent flag, notification channel, critical care flag (medical baseline, life support), and restoration confirmation. Enables customer-facing outage communication and regulatory customer impact reporting.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`customer_notification` (
    `customer_notification_id` BIGINT COMMENT 'Unique surrogate identifier for each customer notification record in the outage management system. Primary key for the customer_notification data product.',
    `account_id` BIGINT COMMENT 'Reference to the customer account receiving this notification. Sourced from the Customer Information System (CIS) in SAP IS-U or Oracle CC&B.',
    `affected_customer_id` BIGINT COMMENT 'Foreign key linking to outage.affected_customer. Business justification: The customer_notification table records notifications sent to customers about outage events, but has no direct FK to the affected_customer association record. The affected_customer table is the author',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to interconnection.interconnection_agreement. Business justification: Notifications to DER customers must comply with interconnection agreement advance notice requirements, export curtailment notification timelines, and special notification provisions for critical DER f',
    `event_id` BIGINT COMMENT 'Reference to the outage event that triggered this notification. Links the notification to the specific unplanned interruption or planned maintenance window in the Outage Management System (OMS).',
    `planned_outage_window_id` BIGINT COMMENT 'Foreign key linking to outage.planned_outage_window. Business justification: The customer_notification table has planned_outage_start_timestamp and planned_outage_end_timestamp as denormalized fields, but no FK to planned_outage_window. Notifications for planned outages must b',
    `premise_id` BIGINT COMMENT 'Foreign key linking to customer.premise. Business justification: Outage notifications are premise-specific (especially for planned outages and life support customers at specific service addresses). customer_notification has account_id but no premise FK; premise-lev',
    `service_point_id` BIGINT COMMENT 'Reference to the specific service delivery point (premise) affected by the outage for which this notification was issued. Enables geographic and network-level analysis of notification coverage.',
    `storm_event_id` BIGINT COMMENT 'Foreign key linking to outage.storm_event. Business justification: The customer_notification table has no FK to storm_event despite notifications being a critical component of storm response operations. During storm events, mass notifications are issued and must be t',
    `acknowledgment_timestamp` TIMESTAMP COMMENT 'Timestamp when the customer acknowledged receipt of this notification. Null if no acknowledgment was received. Used for life-support welfare check compliance and two-way communication analytics.',
    `advance_notice_hours` DECIMAL(18,2) COMMENT 'Number of hours of advance notice provided to the customer prior to a planned outage, calculated as the difference between notification sent timestamp and planned outage start timestamp. Used to verify compliance with state PUC minimum advance notice requirements (typically 48–72 hours).',
    `cause_description` STRING COMMENT 'Human-readable description of the outage cause as communicated to the customer in this notification (e.g., equipment failure on Main St. feeder, storm damage to transmission line). Supports customer transparency and regulatory reporting.',
    `cis_account_number` STRING COMMENT 'The customer account number as recorded in the Customer Information System (CIS) — SAP IS-U or Oracle CC&B — at the time of notification. Provides a direct cross-reference to the billing and service account for regulatory audit and dispute resolution.',
    `contact_address` STRING COMMENT 'The specific contact address (email address, phone number, or device token) used for this notification delivery attempt, as resolved from the customers preference profile. Stored for audit and delivery confirmation purposes. Classified as restricted PII.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp when this notification record was first created in the outage management system. Supports data lineage, audit trail, and regulatory record-keeping requirements.',
    `customer_acknowledgment_flag` BOOLEAN COMMENT 'Indicates whether the customer explicitly acknowledged receipt of this notification (e.g., via IVR keypress, SMS reply, or mobile app confirmation). True = acknowledged. Supports two-way communication tracking and life-support customer welfare checks.',
    `customers_affected_count` STRING COMMENT 'Total number of customers affected by the associated outage event at the time this notification was generated. Included in the notification for context and used in SAIFI (System Average Interruption Frequency Index) reporting.',
    `delivered_timestamp` TIMESTAMP COMMENT 'Timestamp when delivery confirmation was received from the channel provider, confirming the notification reached the customers device, inbox, or IVR endpoint. Null if delivery has not been confirmed or failed.',
    `delivery_status` STRING COMMENT 'Current lifecycle state of the notification delivery attempt. pending: queued for dispatch; sent: transmitted to channel provider; delivered: confirmed receipt by customer device or inbox; failed: delivery attempt unsuccessful; bounced: message returned undeliverable; opted_out: customer has opted out of this channel.. Valid values are `pending|sent|delivered|failed|bounced|opted_out`',
    `etr_timestamp` TIMESTAMP COMMENT 'The Estimated Time to Restore (ETR) communicated to the customer in this notification. Represents the utilitys best estimate of when power will be restored to the affected service point. Critical for customer satisfaction and regulatory ETR accuracy reporting.',
    `failure_reason` STRING COMMENT 'Reason code for notification delivery failure when delivery_status is failed or bounced. Supports channel quality monitoring, contact data hygiene initiatives, and SLA root cause analysis. [ENUM-REF-CANDIDATE: invalid_contact|channel_unavailable|provider_error|customer_opted_out|number_disconnected|mailbox_full|unknown — promote to reference product]',
    `language_code` STRING COMMENT 'ISO 639-1 language code (optionally with ISO 3166-1 country subtag) of the language in which the notification was composed and delivered. Supports multilingual customer communication compliance requirements mandated by state PUCs in diverse service territories.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_retry_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent delivery retry attempt for this notification. Null if no retries have been attempted. Used in conjunction with retry_count to assess delivery persistence and channel failure patterns.',
    `life_support_flag` BOOLEAN COMMENT 'Indicates whether the customer is registered as a life support or medical baseline customer at the time of this notification. True = life support customer. Triggers priority notification handling and regulatory reporting obligations under state PUC medical baseline rules.',
    `message_body` STRING COMMENT 'Full text content of the notification message as delivered to the customer, including outage details, Estimated Time to Restore (ETR), and restoration instructions. Stored for regulatory audit and dispute resolution.',
    `message_subject` STRING COMMENT 'Subject line or headline of the notification as delivered to the customer. Applicable primarily to email and mobile app push notifications. Stored for audit, regulatory review, and communication effectiveness analysis.',
    `notification_batch_number` STRING COMMENT 'Identifier for the batch or campaign in which this notification was grouped and dispatched. Multiple customer notifications for the same outage event are typically dispatched in batches. Supports batch-level delivery performance analysis and storm response coordination.',
    `notification_channel` STRING COMMENT 'Communication channel through which the notification was dispatched to the customer. IVR: Interactive Voice Response automated call; SMS: text message; email: electronic mail; mobile_app: push notification via utility mobile application; web_portal: in-portal alert; postal_mail: physical letter for regulatory advance notice.. Valid values are `ivr|sms|email|mobile_app|web_portal|postal_mail`',
    `notification_number` STRING COMMENT 'Externally visible, human-readable business identifier for this notification record. Used in customer correspondence, regulatory audit trails, and SLA compliance tracking. Format: NTF- followed by 10-digit sequence.. Valid values are `^NTF-[0-9]{10}$`',
    `notification_priority` STRING COMMENT 'Priority level assigned to this notification, governing dispatch queue order and retry escalation logic. Critical priority is used for life-support customers and medical baseline accounts. Supports regulatory requirements for prioritized restoration communication.. Valid values are `critical|high|standard|low`',
    `notification_type` STRING COMMENT 'Classification of the notification purpose. outage_alert: initial unplanned outage alert; etr_update: Estimated Time to Restore (ETR) revision; restoration_confirmation: power restored confirmation; planned_outage_notice: advance notice of scheduled maintenance; safety_alert: safety-related communication; demand_response_event: Demand Response (DR) program event notice.. Valid values are `outage_alert|etr_update|restoration_confirmation|planned_outage_notice|safety_alert|demand_response_event`',
    `oms_notification_ref` STRING COMMENT 'External reference identifier assigned by the Outage Management System (OMS), specifically GE PowerOn ADMS, to this notification record. Enables bidirectional traceability between the lakehouse silver layer and the operational OMS source system.',
    `opt_out_flag` BOOLEAN COMMENT 'Indicates whether the customer had opted out of this notification channel or notification type at the time of dispatch. True = customer opted out; notification may have been suppressed or sent via alternate channel per preference rules. Critical for TCPA and state PUC opt-out compliance.',
    `outage_start_timestamp` TIMESTAMP COMMENT 'The timestamp of the outage event start as communicated to the customer in this notification. Provides the customer with context on when the interruption began. Used in SAIDI/SAIFI/CAIDI reliability index calculations.',
    `outage_type` STRING COMMENT 'Classification of the outage event type associated with this notification. Distinguishes between unplanned interruptions, scheduled maintenance windows, storm-related events, equipment failures, and transmission faults. Supports SAIDI/SAIFI/CAIDI reliability metric segmentation.. Valid values are `unplanned|planned|storm_related|equipment_failure|transmission_fault`',
    `regulatory_notice_flag` BOOLEAN COMMENT 'Indicates whether this notification fulfills a specific regulatory advance notice obligation (e.g., state PUC-mandated 48-hour advance notice for planned outages). True = this notification is a regulatory compliance notice. Supports regulatory reporting and audit evidence.',
    `retry_count` STRING COMMENT 'Number of delivery retry attempts made for this notification after an initial failure. Used to track delivery persistence, diagnose channel reliability issues, and support SLA compliance reporting.',
    `sent_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp when the notification was dispatched from the utilitys outage communication platform to the delivery channel provider. Used as the primary business event time for SLA measurement and regulatory compliance reporting.',
    `sla_met_flag` BOOLEAN COMMENT 'Indicates whether this notification was dispatched within the required Service Level Agreement (SLA) target time. True = SLA met; False = SLA breached. Supports regulatory SLA compliance reporting to state PUCs and internal performance dashboards.',
    `sla_target_minutes` STRING COMMENT 'The Service Level Agreement (SLA) target time in minutes within which this notification type must be dispatched following the triggering outage event. Defined by state PUC regulations and internal communication standards. Used as the benchmark for SLA compliance measurement.',
    `source_system` STRING COMMENT 'Identifies the operational system of record that originated this notification record. Primarily GE PowerOn ADMS for OMS-driven notifications, but may include SAP IS-U, Oracle CC&B for billing-related outage notices, or manual OMS entries during storm response.. Valid values are `GE_PowerOn_ADMS|SAP_ISU|Oracle_CCB|OMS_Manual|DERMS`',
    `territory_code` STRING COMMENT 'Code identifying the utilitys service territory or operating division within which the affected customer and service point are located. Supports territory-level SLA compliance reporting to individual state PUCs and regional storm response performance analysis.. Valid values are `^[A-Z]{2,6}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp of the most recent modification to this notification record, such as a delivery status update or retry attempt. Supports change tracking and SLA audit.',
    CONSTRAINT pk_customer_notification PRIMARY KEY(`customer_notification_id`)
) COMMENT 'Record of outage-related notifications sent to customers via IVR, SMS, email, or mobile app. Captures notification type (outage alert, ETR update, restoration confirmation, planned outage advance notice), channel, delivery timestamp, delivery status, customer preference reference, and opt-out flag. Supports regulatory requirements for advance notice of planned outages and tracks communication SLA compliance.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`storm_event` (
    `storm_event_id` BIGINT COMMENT 'Unique surrogate identifier for the storm event record in the Outage Management System (OMS). Primary key for the storm_event entity.',
    `control_area_id` BIGINT COMMENT 'Foreign key linking to grid.control_area. Business justification: Storm events are scoped to a control area for NERC OE-417 reporting and balancing authority coordination. The control area defines the operational boundary for storm response and mutual aid activation',
    `zone_id` BIGINT COMMENT 'Foreign key linking to forecast.zone. Business justification: Storm events impact specific forecast zones. Utilities track zone-level storm impacts for Major Event Day (MED) threshold calculations, mutual aid resource allocation, and regulatory reporting (IEEE 1',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Major storm events trigger specific regulatory reporting obligations (NERC EOP-004 emergency operations, state PUC emergency reporting requirements). Compliance teams track which obligations are activ',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Major storm events trigger mandatory DOE OE-417 emergency filings and PUC major event day reports. Storm_event tracks oe417_filing_required and oe417_filing_timestamp but lacks FK to the actual filing',
    `service_territory_id` BIGINT COMMENT 'Reference to the primary service territory affected by the storm event. Links to the geographic service area definition used for regulatory reporting and customer impact scoping.',
    `weather_input_id` BIGINT COMMENT 'Foreign key linking to forecast.weather_input. Business justification: Storm event severity tracking and post-event analysis require actual weather data (temperature, wind speed, precipitation) for regulatory reporting, insurance claims, and operational review. Weather i',
    `affected_distribution_circuits` STRING COMMENT 'Number of distribution circuits (below 69kV) that experienced outages or damage during this storm event. Key metric for distribution storm damage assessment and restoration prioritization.',
    `affected_region_description` STRING COMMENT 'Free-text description of the geographic area impacted by the storm, including counties, cities, or distribution circuits affected. Supplements the service territory reference for regulatory filings and public communications.',
    `affected_transmission_lines` STRING COMMENT 'Number of transmission lines (69kV and above) that experienced outages or damage during this storm event. Used for NERC reliability reporting and transmission damage assessment.',
    `after_action_report_reference` STRING COMMENT 'Document management reference number or URL for the post-storm After-Action Report (AAR) filed following storm demobilization. Used for continuous improvement tracking and regulatory compliance.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time this storm event record was first created in the OMS or data platform. Used for audit trail and data lineage tracking.',
    `critical_facilities_affected` STRING COMMENT 'Number of critical facilities (hospitals, emergency services, water treatment plants, shelters) that experienced power interruptions during this storm event. Drives restoration prioritization and regulatory reporting.',
    `customer_notification_issued` BOOLEAN COMMENT 'Indicates whether proactive customer notifications (via IVR, SMS, email, or web portal) were issued for this storm event. Supports PUC customer communication compliance tracking.',
    `declared_end_time` TIMESTAMP COMMENT 'The date and time at which the storm event was officially closed and storm response operations were demobilized. Null if the storm is still active.',
    `declared_start_time` TIMESTAMP COMMENT 'The date and time at which the storm event was officially declared by the utilitys emergency operations center, triggering storm response activation. Principal business event timestamp for the storm lifecycle.',
    `emergency_operations_center_activated` BOOLEAN COMMENT 'Indicates whether the utilitys Emergency Operations Center (EOC) was formally activated for this storm event. EOC activation triggers escalated staffing, executive involvement, and enhanced regulatory reporting obligations.',
    `eoc_activation_time` TIMESTAMP COMMENT 'Date and time the Emergency Operations Center (EOC) was formally activated for this storm event. Null if EOC was not activated.',
    `eoc_deactivation_time` TIMESTAMP COMMENT 'Date and time the Emergency Operations Center (EOC) was formally deactivated following storm response demobilization. Null if EOC is still active.',
    `estimated_storm_cost_usd` DECIMAL(18,2) COMMENT 'Estimated total cost of storm response operations in US dollars, including labor (internal and mutual aid), materials, equipment, and contractor costs. Used for regulatory cost recovery filings and executive reporting. Actual costs tracked in SAP S/4HANA.',
    `external_crews_deployed` STRING COMMENT 'Actual number of external line crews that arrived and were deployed during this storm event. Compared against requested count for mutual aid effectiveness analysis.',
    `external_crews_requested` STRING COMMENT 'Number of external line crews requested through mutual aid for this storm event. Used for resource planning, cost tracking, and post-storm mutual aid reconciliation.',
    `fema_disaster_declaration_number` STRING COMMENT 'FEMA federal disaster declaration number associated with this storm event, if applicable. Required for federal cost reimbursement claims and regulatory filings when a presidential disaster declaration is issued.',
    `first_customer_notification_time` TIMESTAMP COMMENT 'Date and time the first proactive customer notification was issued for this storm event. Used for PUC compliance reporting on customer communication timeliness.',
    `incident_commander` STRING COMMENT 'Name of the designated Incident Commander responsible for overall storm response operations under the Incident Command System (ICS). Used for accountability, communications, and post-storm after-action review.',
    `is_major_event_day` BOOLEAN COMMENT 'Indicates whether this storm event qualifies as a Major Event Day (MED) per IEEE 1366-2012 statistical threshold methodology. When True, outages during this event are excluded from SAIDI/SAIFI/CAIDI reliability index calculations for regulatory reporting.',
    `is_mutual_aid_requested` BOOLEAN COMMENT 'Indicates whether mutual aid from other utilities or the regional mutual aid group was formally requested for this storm event. Triggers mutual aid tracking, cost allocation, and regulatory reporting obligations.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time this storm event record was most recently modified. Used for change tracking, data freshness monitoring, and audit compliance.',
    `med_threshold_saidi` DECIMAL(18,2) COMMENT 'The calculated SAIDI threshold value (in minutes per customer) used to determine MED qualification for this event year, per IEEE 1366-2012 beta method. Stored for audit and regulatory verification purposes.',
    `meteorological_end_time` TIMESTAMP COMMENT 'The date and time the weather event physically ended impacting the service territory per NWS or internal meteorological data. Used for IEEE 1366 MED exclusion period boundary calculations.',
    `meteorological_start_time` TIMESTAMP COMMENT 'The date and time the weather event physically began impacting the service territory, as reported by the National Weather Service or internal meteorological data. May precede the declared start time.',
    `mutual_aid_coordinator` STRING COMMENT 'Name of the regional mutual aid coordinator organization or agreement (e.g., EEI Mutual Aid, Southeast Mutual Aid Group) through which external crews were requested.',
    `mutual_aid_request_time` TIMESTAMP COMMENT 'Date and time the formal mutual aid request was submitted to the regional mutual aid coordinator or neighboring utilities. Null if no mutual aid was requested.',
    `nerc_event_type` STRING COMMENT 'NERC event classification code for mandatory regulatory reporting. EEA1/EEA2/EEA3 indicate Emergency Energy Alert levels; MEA indicates a Misoperation Event Alert; OE417 indicates a DOE Electric Emergency Incident and Disturbance Report filing requirement. [ENUM-REF-CANDIDATE: EEA1|EEA2|EEA3|MEA|OE417|other|not_applicable — 7 candidates stripped; promote to reference product]',
    `nws_storm_code` STRING COMMENT 'External identifier assigned by the National Weather Service (NWS) to the weather event, used to cross-reference official meteorological data, storm tracks, and NWS storm reports for regulatory and insurance purposes.',
    `oe417_filing_required` BOOLEAN COMMENT 'Indicates whether this storm event meets the threshold requiring a DOE OE-417 Electric Emergency Incident and Disturbance Report filing. Triggered when 50,000+ customers are affected or critical infrastructure is impacted.',
    `oe417_filing_timestamp` TIMESTAMP COMMENT 'Date and time the DOE OE-417 Electric Emergency Incident and Disturbance Report was submitted for this storm event. Null if filing not required or not yet submitted.',
    `peak_customers_affected` STRING COMMENT 'Maximum number of customers simultaneously without power at any point during the storm event. Key metric for regulatory reporting, mutual aid justification, and public communications. Sourced from OMS outage aggregation.',
    `puc_notification_required` BOOLEAN COMMENT 'Indicates whether this storm event requires formal notification to the state Public Utility Commission (PUC) per state-specific emergency reporting thresholds (e.g., >10% of customers affected or extended outage duration).',
    `puc_notification_timestamp` TIMESTAMP COMMENT 'Date and time the formal notification was submitted to the state Public Utility Commission (PUC) for this storm event. Null if notification not required or not yet submitted.',
    `response_activation_level` STRING COMMENT 'Numeric level (1–5) indicating the severity of the storm response activation, where Level 1 is routine and Level 5 is maximum emergency mobilization. Determines staffing, resource deployment, and executive notification thresholds.',
    `response_status` STRING COMMENT 'Current lifecycle state of the storm response operation. Drives workflow routing in OMS and determines whether mutual aid, crew dispatch, and cost tracking are active.. Valid values are `declared|active|demobilizing|closed|cancelled`',
    `storm_cost_reference` STRING COMMENT 'Reference code linking this storm event to the corresponding cost collection object in SAP S/4HANA (e.g., WBS element, internal order, or cost center) for storm cost tracking, regulatory cost recovery filings, and OPEX reporting.',
    `storm_name` STRING COMMENT 'Human-readable name assigned to the storm event (e.g., Hurricane Ida, Winter Storm Uri, Derecho 2023-07). Used for communications, regulatory reporting, and historical reference.',
    `storm_notes` STRING COMMENT 'Free-text operational notes and situational awareness comments entered by storm coordinators during the event lifecycle. Captures key decisions, escalations, and observations not captured in structured fields.',
    `storm_number` STRING COMMENT 'Externally-known business identifier for the storm event, used in OMS, regulatory filings, and mutual aid coordination. Format: STM-{YYYY}-{NNNNN}.. Valid values are `^STM-[0-9]{4}-[0-9]{5}$`',
    `storm_to_outage_events` BIGINT COMMENT 'FK to outage.outage_event.outage_event_id — A storm event groups multiple outage events under coordinated response. This parent-child link is essential for storm response management and MED calculations.',
    `storm_type` STRING COMMENT 'Classification of the weather event type driving storm response operations. Determines response protocols, mutual aid triggers, and IEEE 1366 Major Event Day (MED) classification criteria. [ENUM-REF-CANDIDATE: hurricane|ice_storm|derecho|tornado|heat_event|winter_storm|thunderstorm|flood|wildfire|other — promote to reference product]',
    `total_customer_interruptions` STRING COMMENT 'Cumulative count of individual customer interruption events associated with this storm, accounting for customers who experienced multiple outages. Used in SAIFI calculation inputs for IEEE 1366 reporting.',
    `total_outage_events` STRING COMMENT 'Total number of discrete outage events (trouble calls, switching events, fault isolations) grouped under this storm event in the OMS. Used for storm complexity assessment and resource planning.',
    CONSTRAINT pk_storm_event PRIMARY KEY(`storm_event_id`)
) COMMENT 'Master record for a declared storm or major weather event that triggers storm response operations. Captures storm name, storm type (hurricane, ice storm, derecho, tornado, heat event), declared start and end times, affected service territory, Major Event Day (MED) declaration flag per IEEE 1366, storm response activation level (e.g., Level 1-5), mutual aid request flag, total estimated affected customers at peak, and storm cost tracking reference. Parent entity for grouping multiple outage events and mutual aid requests under a single coordinated storm response.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`mutual_aid_request` (
    `mutual_aid_request_id` BIGINT COMMENT 'Unique surrogate identifier for the mutual aid request record. Primary key for this entity in the Silver Layer lakehouse.',
    `control_area_id` BIGINT COMMENT 'Foreign key linking to grid.control_area. Business justification: Mutual aid requests are scoped to the requesting utilitys control area, which defines the geographic and operational boundary of the emergency. NERC ESOP and regional mutual aid agreements are organi',
    `event_id` BIGINT COMMENT 'Reference to the outage event that triggered this mutual aid request. Links the aid request to the specific storm, major outage, or emergency event driving the need for external resources.',
    `storm_event_id` BIGINT COMMENT 'FK to outage.storm_event.storm_event_id — Mutual aid requests are issued in context of a storm event. Must link to parent storm for coordination and cost tracking.',
    `weather_input_id` BIGINT COMMENT 'Foreign key linking to forecast.weather_input. Business justification: Mutual aid deployment decisions require weather forecast data to determine crew mobilization timing, staging locations, and resource quantities. Weather severity forecasts justify mutual aid requests ',
    `acknowledgement_timestamp` TIMESTAMP COMMENT 'Date and time when the responding utility formally acknowledged receipt of the mutual aid request. Used to measure response time SLA compliance.',
    `actual_cost_usd` DECIMAL(18,2) COMMENT 'Actual total cost in US dollars incurred for the mutual aid deployment upon demobilization, as submitted by the responding utility for reimbursement. Populated after demobilization and cost reconciliation.',
    `affected_customers_count` STRING COMMENT 'Number of customers without power at the time the mutual aid request was issued. Provides context for the scale of the outage event and justifies the level of external resource request.',
    `arrival_date` DATE COMMENT 'Actual date on which the responding utilitys crews arrived at the staging area or work location within the requesting utilitys service territory and became available for restoration work.',
    `commitment_timestamp` TIMESTAMP COMMENT 'Date and time when the responding utility formally committed to providing the requested resources, transitioning the request from acknowledged to committed status.',
    `cost_reimbursement_flag` BOOLEAN COMMENT 'Indicates whether the requesting utility has agreed to reimburse the responding utility for costs incurred during the mutual aid deployment. True = reimbursable; False = non-reimbursable (goodwill aid). Drives cost tracking and invoice generation workflows.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this mutual aid request record was first created in the system. Audit trail field for data lineage and compliance purposes.',
    `crew_count_committed` STRING COMMENT 'Number of crew units actually committed by the responding utility. May be less than crew_count_requested if the responding utility has limited available resources.',
    `crew_count_deployed` STRING COMMENT 'Actual number of crew units that physically arrived and performed restoration work in the requesting utilitys territory. May differ from committed count due to last-minute changes or attrition during transit.',
    `crew_count_requested` STRING COMMENT 'Number of crew units (typically crew trucks or work teams) requested from the responding utility. A crew unit typically consists of a truck and associated personnel per ESOP standards.',
    `crew_type_committed` STRING COMMENT 'Classification of crew type actually committed by the responding utility. May differ from crew_type_requested if the responding utility can only provide a partial or alternative resource match. [ENUM-REF-CANDIDATE: line_crew|tree_crew|damage_assessment|substation|transmission|logistics — promote to reference product]',
    `crew_type_requested` STRING COMMENT 'Classification of crew type requested by the requesting utility (e.g., line crew, tree trimming crew, damage assessment crew, substation crew, transmission crew, logistics crew). Drives resource matching in ESOP coordination. [ENUM-REF-CANDIDATE: line_crew|tree_crew|damage_assessment|substation|transmission|logistics — promote to reference product]',
    `demobilization_date` DATE COMMENT 'Actual date on which the responding utilitys crews completed their assignment and were released to return to their home utility. Marks the end of active mutual aid deployment.',
    `equipment_count_committed` STRING COMMENT 'Number of equipment units of the specified type actually committed by the responding utility.',
    `equipment_count_requested` STRING COMMENT 'Number of equipment units of the specified type requested from the responding utility.',
    `equipment_type_requested` STRING COMMENT 'Type of specialized equipment requested alongside crews, such as bucket trucks, digger derricks, cable pullers, generators, or mobile command units. Supplements crew type in resource matching.',
    `esop_reference_number` STRING COMMENT 'Reference number of the Emergency Support Operations Plan (ESOP) or mutual aid agreement under which this request is issued. Ties the request to the governing bilateral or regional aid compact.',
    `estimated_cost_usd` DECIMAL(18,2) COMMENT 'Estimated total cost in US dollars for the mutual aid deployment, including labor, equipment, lodging, and travel expenses. Used for budget planning and pre-authorization of reimbursable aid.',
    `event_type` STRING COMMENT 'Classification of the weather or emergency event that triggered the mutual aid request. Used for post-event analysis, NERC regulatory reporting, and storm response benchmarking. [ENUM-REF-CANDIDATE: hurricane|ice_storm|tornado|wildfire|flood|earthquake|major_outage|other — promote to reference product]',
    `invoice_status` STRING COMMENT 'Current status of the cost reimbursement invoice associated with this mutual aid request. Tracks the financial settlement lifecycle from invoice submission through payment or dispute resolution.. Valid values are `not_applicable|pending|submitted|approved|paid|disputed`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this mutual aid request record was most recently modified. Supports change tracking, audit compliance, and Silver Layer incremental processing.',
    `mobilization_date` DATE COMMENT 'Planned or actual date on which the committed crews and resources depart from the responding utility and begin travel to the requesting utilitys service territory.',
    `nerc_reportable_flag` BOOLEAN COMMENT 'Indicates whether this mutual aid request must be reported to NERC under EOP-005-3 or other applicable reliability standards. True = reportable event requiring NERC submission.',
    `nerc_submission_timestamp` TIMESTAMP COMMENT 'Date and time when this mutual aid event was submitted to NERC for regulatory reporting. Null if nerc_reportable_flag is False or submission is pending.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or coordination details associated with the mutual aid request. May include staging instructions, safety briefing requirements, or special equipment needs.',
    `oms_event_reference` STRING COMMENT 'Reference identifier from the Outage Management System (GE PowerOn ADMS) for the outage event associated with this mutual aid request. Enables traceability between the aid request and the OMS event record.',
    `priority_level` STRING COMMENT 'Priority classification of the mutual aid request, reflecting the severity of the outage event and urgency of resource need. Drives dispatch sequencing when multiple requests compete for limited responding utility resources.. Valid values are `critical|high|medium|low`',
    `regional_mutual_aid_group` STRING COMMENT 'Name of the regional mutual aid compact or group under which this request is coordinated (e.g., Southeast Electric Exchange, Mid-Atlantic Mutual Aid Group, Midwest Mutual Aid Group). Identifies the regional coordination framework.',
    `request_date` TIMESTAMP COMMENT 'Date and time when the mutual aid request was formally submitted by the requesting utility. Serves as the principal business event timestamp for the request lifecycle.',
    `request_number` STRING COMMENT 'Externally-known business identifier for the mutual aid request, used in inter-utility communications, ESOP documentation, and regulatory reporting. Format: MAR-{YYYY}-{NNNNNN}.. Valid values are `^MAR-[0-9]{4}-[0-9]{6}$`',
    `request_status` STRING COMMENT 'Current lifecycle state of the mutual aid request, tracking progression from initial submission through crew mobilization, active deployment, and final demobilization or cancellation. [ENUM-REF-CANDIDATE: draft|submitted|acknowledged|committed|active|demobilized|cancelled|closed — promote to reference product]',
    `request_type` STRING COMMENT 'Indicates whether this utility is the requesting party (outbound — this utility is seeking aid from a neighbor) or the responding party (inbound — this utility is providing aid to a neighbor).. Valid values are `outbound|inbound`',
    `requesting_contact_name` STRING COMMENT 'Name of the primary operational contact at the requesting utility responsible for coordinating the mutual aid request and managing incoming crews.',
    `requesting_contact_phone` STRING COMMENT 'Direct phone number for the primary operational contact at the requesting utility. Used for real-time coordination during storm response.. Valid values are `^+?[0-9-s()]{7,20}$`',
    `requesting_utility_name` STRING COMMENT 'Legal name of the utility that is requesting mutual aid resources. Identifies the party in need of crew or equipment support during a major outage or storm event.',
    `requesting_utility_nerc_code` STRING COMMENT 'NERC-assigned registered entity identifier for the requesting utility, used for regulatory reporting and inter-utility coordination under NERC EOP standards.',
    `responding_contact_name` STRING COMMENT 'Name of the primary operational contact at the responding utility responsible for coordinating crew dispatch and resource commitment.',
    `responding_contact_phone` STRING COMMENT 'Direct phone number for the primary operational contact at the responding utility. Used for real-time coordination during crew mobilization.. Valid values are `^+?[0-9-s()]{7,20}$`',
    `responding_utility_name` STRING COMMENT 'Legal name of the utility that is committing resources in response to the mutual aid request. Identifies the aid-providing party.',
    `responding_utility_nerc_code` STRING COMMENT 'NERC-assigned registered entity identifier for the responding (aid-providing) utility, used for regulatory reporting and inter-utility coordination.',
    `service_territory_state` STRING COMMENT 'Two-letter US state code for the primary service territory where restoration work will be performed. Used for jurisdictional compliance, state PUC reporting, and logistics planning.. Valid values are `^[A-Z]{2}$`',
    `staging_location` STRING COMMENT 'Name or address of the staging area designated for incoming mutual aid crews within the requesting utilitys service territory. Used for logistics coordination and crew check-in management.',
    CONSTRAINT pk_mutual_aid_request PRIMARY KEY(`mutual_aid_request_id`)
) COMMENT 'Record of a mutual aid request issued to or received from neighboring utilities during large-scale storm response or major outage events. Captures requesting utility, responding utility, request date, crew type and count requested, crew type and count committed, mobilization date, demobilization date, ESOP (Emergency Support Operations Plan) reference, and cost reimbursement tracking flag. Supports NERC EOP mutual aid obligations and storm recovery coordination.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`reliability_index_period` (
    `reliability_index_period_id` BIGINT COMMENT 'Primary key for reliability_index_period',
    `control_area_id` BIGINT COMMENT 'Foreign key linking to grid.control_area. Business justification: SAIDI/SAIFI reliability indices are computed and reported per control area for NERC BAL and PUC regulatory filings. The control area is the primary reporting boundary for reliability performance. Doma',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: SAIDI/SAIFI/CAIDI reporting is mandated by specific PUC obligations with defined performance thresholds and filing deadlines. Regulatory affairs maps each reporting period to the governing obligation ',
    `zone_id` BIGINT COMMENT 'Foreign key linking to forecast.zone. Business justification: Reliability indices (SAIDI, SAIFI, CAIDI) are calculated and reported by forecast zone for state PUC regulatory compliance and performance benchmarking. Forecast zones define geographic reporting boun',
    `amendment_reason` STRING COMMENT 'Free-text description of the reason for amending or recomputing this reliability index period record (e.g., data correction from OMS, reclassification of MED events, customer count correction). Required for version_number greater than 1. Supports regulatory audit trail and PUC amendment filing documentation.',
    `approved_by` STRING COMMENT 'Identifier or name of the authorized utility employee (typically a Reliability Engineer or Director of Grid Operations) who approved this reliability index period record for regulatory filing. Supports SOX internal control documentation and regulatory audit requirements.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this reliability index period record was formally approved for regulatory filing. Supports SOX internal control audit trails and regulatory submission documentation.',
    `caidi_minutes` DECIMAL(18,2) COMMENT 'Customer Average Interruption Duration Index expressed in minutes per interruption. Computed as total_customer_minutes_interrupted divided by total_customer_interruptions (equivalently, SAIDI divided by SAIFI). Represents the average duration of each interruption experienced by affected customers. Used to assess restoration performance.',
    `caidi_normalized_minutes` DECIMAL(18,2) COMMENT 'CAIDI value computed after excluding Major Event Day (MED) interruptions per IEEE 1366 normalization methodology. Derived from normalized SAIDI and SAIFI values. Used for PUC performance standard compliance and restoration performance benchmarking.',
    `computation_method` STRING COMMENT 'Identifies the specific computational methodology applied to derive the reliability indices in this record. IEEE_1366_STANDARD applies the full IEEE 1366 methodology including MEDs; IEEE_1366_MED_EXCLUDED applies the normalized MED-excluded methodology; PUC_CUSTOM applies a state-specific PUC-mandated variation; NERC_BENCHMARK applies NERC benchmarking methodology.. Valid values are `IEEE_1366_STANDARD|IEEE_1366_MED_EXCLUDED|PUC_CUSTOM|NERC_BENCHMARK`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this reliability index period record was first created in the system. Supports data lineage, audit trail, and SOX internal control requirements.',
    `customers_served` STRING COMMENT 'Total number of customers served within the reporting entity boundary during the reporting period. This is the denominator used in SAIDI and SAIFI index calculations per IEEE 1366. Typically represents the average or end-of-period customer count as defined by the applicable PUC methodology.',
    `equipment_failure_outage_events` STRING COMMENT 'Number of outage events during the reporting period caused by equipment failure (excluding storm and third-party causes). Supports asset reliability analysis, maintenance planning, and capital investment justification for aging infrastructure programs.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this reliability index period record was most recently modified. Tracks amendments, recomputations, and corrections to the reliability indices. Supports audit trail and regulatory amendment documentation.',
    `maifi_index` DECIMAL(18,2) COMMENT 'Momentary Average Interruption Frequency Index computed as total momentary customer interruptions divided by customers served. Measures the frequency of brief power interruptions (five minutes or less) per customer. Increasingly required by PUCs as a power quality metric alongside SAIDI and SAIFI.',
    `med_event_count` STRING COMMENT 'Number of calendar days during the reporting period that qualified as Major Event Days (MEDs) per the IEEE 1366 beta + 2.5 sigma threshold methodology. Used to assess storm and extreme weather impact on reliability performance.',
    `med_excluded_customer_interruptions` STRING COMMENT 'Total customer interruptions attributable to Major Event Days (MEDs) that are excluded from the normalized IEEE 1366 index calculations. MEDs are days where the daily SAIDI exceeds a statistically derived threshold (beta + 2.5 sigma). Tracking this separately enables both total and MED-excluded reporting as required by most PUCs.',
    `med_excluded_customer_minutes` DECIMAL(18,2) COMMENT 'Total customer minutes interrupted attributable to Major Event Days (MEDs) that are excluded from the normalized IEEE 1366 index calculations. Used to compute MED-normalized SAIDI and SAIFI values required for PUC regulatory filings and NERC benchmarking.',
    `med_threshold_saidi_minutes` DECIMAL(18,2) COMMENT 'The computed daily SAIDI threshold (beta + 2.5 sigma) used to classify a calendar day as a Major Event Day for this reporting period. Derived from the five-year historical daily SAIDI distribution per IEEE 1366 methodology. Documents the MED classification boundary applied to this period.',
    `momentary_interruption_count` STRING COMMENT 'Total number of momentary interruptions (duration five minutes or less per IEEE 1366 definition) experienced by customers during the reporting period. Used to compute MAIFI (Momentary Average Interruption Frequency Index) and assess power quality performance.',
    `nerc_registered_entity_code` STRING COMMENT 'NERC Compliance Registry identifier for the utility entity responsible for this reliability report. Required for NERC reliability standard compliance submissions and benchmarking participation. Aligns with the NERC Transmission Planner, Distribution Provider, or Load-Serving Entity registration.',
    `oms_source_system_code` STRING COMMENT 'Identifier of the Outage Management System (OMS) instance from which the underlying outage event data was sourced for this reliability index computation. Supports data lineage tracing back to GE PowerOn ADMS or equivalent OMS. Critical for audit and regulatory filing validation.',
    `period_end_date` DATE COMMENT 'Calendar date marking the inclusive end of the reliability reporting period. Combined with period_start_date to define the exact window over which SAIDI, SAIFI, and CAIDI indices are computed.',
    `period_start_date` DATE COMMENT 'Calendar date marking the inclusive start of the reliability reporting period. Combined with period_end_date to define the exact window over which SAIDI, SAIFI, and CAIDI indices are computed.',
    `period_type` STRING COMMENT 'Classification of the reporting period granularity. Determines the aggregation window for SAIDI, SAIFI, and CAIDI index calculations. MONTHLY is used for operational monitoring; QUARTERLY and ANNUAL are used for PUC regulatory filings; ROLLING_12_MONTH is used for NERC benchmarking.. Valid values are `MONTHLY|QUARTERLY|ANNUAL|ROLLING_12_MONTH`',
    `planned_interruption_customer_minutes` DECIMAL(18,2) COMMENT 'Customer minutes interrupted attributable to planned (scheduled maintenance) outage events during the reporting period. Some PUC jurisdictions require separate reporting of planned vs. unplanned interruptions. Enables decomposition of total CMI into planned and unplanned components.',
    `prior_period_saidi_minutes` DECIMAL(18,2) COMMENT 'SAIDI value from the immediately preceding equivalent reporting period (e.g., prior month, prior quarter, prior year) for the same reporting entity. Stored on the record to support period-over-period variance analysis in regulatory filings without requiring a self-join.',
    `prior_period_saifi_index` DECIMAL(18,2) COMMENT 'SAIFI value from the immediately preceding equivalent reporting period for the same reporting entity. Stored on the record to support period-over-period variance analysis in regulatory filings without requiring a self-join.',
    `puc_jurisdiction_code` STRING COMMENT 'Two-letter state code plus PUC suffix identifying the state Public Utility Commission jurisdiction under which this reliability index period record is filed (e.g., CA-PUC, NY-PUC, TX-PUC). Determines applicable performance standards, reporting formats, and filing deadlines.. Valid values are `^[A-Z]{2}-PUC$`',
    `puc_saidi_performance_target` DECIMAL(18,2) COMMENT 'Regulatory SAIDI performance target (in minutes) established by the applicable state PUC for the reporting period and reporting entity. Used to assess compliance with performance-based rate mechanisms and potential penalty or incentive triggers. Null if no PUC target applies to this reporting level.',
    `puc_saifi_performance_target` DECIMAL(18,2) COMMENT 'Regulatory SAIFI performance target established by the applicable state PUC for the reporting period and reporting entity. Used to assess compliance with performance-based rate mechanisms and potential penalty or incentive triggers. Null if no PUC target applies to this reporting level.',
    `puc_target_met` BOOLEAN COMMENT 'Indicates whether the utility met all applicable PUC reliability performance targets (SAIDI and SAIFI) for this reporting period and reporting entity. True if all applicable targets were met; False if one or more targets were missed. Null if no PUC targets apply. Drives performance-based rate adjustment calculations.',
    `reporting_entity_code` STRING COMMENT 'Business identifier for the specific entity (circuit ID, substation code, PUC territory code, operating area code, or system-level identifier) at which the reliability indices are reported. Corresponds to the reporting_level classification. For SYSTEM level, this is the utility NERC registered entity identifier.',
    `reporting_entity_name` STRING COMMENT 'Human-readable name of the reporting entity (e.g., circuit name, substation name, PUC territory name, operating area name). Used for display in regulatory filings and reliability performance dashboards.',
    `reporting_level` STRING COMMENT 'Organizational or geographic granularity at which the reliability indices are computed and reported. SYSTEM represents the full utility service territory; CIRCUIT and SUBSTATION represent distribution-level granularity; PUC_TERRITORY aligns with regulatory jurisdiction boundaries; OPERATING_AREA represents internal operational divisions.. Valid values are `SYSTEM|CIRCUIT|SUBSTATION|PUC_TERRITORY|OPERATING_AREA`',
    `reporting_period_code` STRING COMMENT 'Externally-known business identifier for the reporting period, encoding the period type and calendar reference (e.g., MONTHLY-2024-03, QUARTERLY-2024-Q1, ANNUAL-2024). Used as the primary business key for regulatory filings and cross-system reconciliation.. Valid values are `^(MONTHLY|QUARTERLY|ANNUAL)-[0-9]{4}(-Q[1-4]|-[0-1][0-9])?$`',
    `saidi_minutes` DECIMAL(18,2) COMMENT 'System Average Interruption Duration Index expressed in minutes per customer. Computed as total_customer_minutes_interrupted divided by customers_served. Represents the average total duration of interruptions experienced per customer during the reporting period. Primary reliability metric for PUC regulatory filings and NERC benchmarking.',
    `saidi_normalized_minutes` DECIMAL(18,2) COMMENT 'SAIDI value computed after excluding Major Event Day (MED) interruptions per IEEE 1366 normalization methodology. Computed as (total_customer_minutes_interrupted minus med_excluded_customer_minutes) divided by customers_served. This is the primary metric used for year-over-year performance benchmarking and PUC performance standard compliance.',
    `saifi_index` DECIMAL(18,2) COMMENT 'System Average Interruption Frequency Index expressed as interruptions per customer. Computed as total_customer_interruptions divided by customers_served. Represents the average number of interruptions experienced per customer during the reporting period. Key reliability metric for PUC regulatory filings.',
    `saifi_normalized_index` DECIMAL(18,2) COMMENT 'SAIFI value computed after excluding Major Event Day (MED) interruptions per IEEE 1366 normalization methodology. Computed as (total_customer_interruptions minus med_excluded_customer_interruptions) divided by customers_served. Used for PUC performance standard compliance and NERC benchmarking.',
    `storm_related_outage_events` STRING COMMENT 'Number of outage events during the reporting period that were classified as storm-related (weather-caused). Supports storm impact analysis, MED classification validation, and regulatory storm reporting requirements. Sourced from OMS event cause codes.',
    `third_party_outage_events` STRING COMMENT 'Number of outage events during the reporting period caused by third parties (e.g., vehicle accidents, dig-ins, animal contacts, vegetation encroachment by non-utility parties). Some PUC jurisdictions allow exclusion of third-party caused outages from performance standard calculations.',
    `total_customer_interruptions` STRING COMMENT 'Total number of customer interruptions (sum of customers affected across all outage events) during the reporting period. This is the numerator for SAIFI calculation. Each customer affected by each distinct outage event counts as one interruption.',
    `total_customer_minutes_interrupted` DECIMAL(18,2) COMMENT 'Sum of the product of customers affected multiplied by outage duration in minutes across all outage events in the reporting period. This is the numerator for SAIDI calculation, expressed in customer-minutes. Also referred to as Customer Minutes of Interruption (CMI) in regulatory filings.',
    `total_outage_events` STRING COMMENT 'Total number of distinct outage events (interruption incidents) that occurred within the reporting entity boundary during the reporting period. Provides context for interpreting SAIDI and SAIFI values and supports frequency-based reliability analysis.',
    `unplanned_interruption_customer_minutes` DECIMAL(18,2) COMMENT 'Customer minutes interrupted attributable to unplanned (forced/fault) outage events during the reporting period. Unplanned interruptions are the primary driver of reliability index degradation and are the focus of most PUC performance standards.',
    `version_number` STRING COMMENT 'Sequential version number incremented each time this reliability index period record is amended or recomputed. Version 1 represents the initial filing; subsequent versions represent amendments. Supports regulatory amendment tracking and audit trail requirements.',
    CONSTRAINT pk_reliability_index_period PRIMARY KEY(`reliability_index_period_id`)
) COMMENT 'Periodic reliability performance record capturing computed SAIDI, SAIFI, and CAIDI index values for a defined reporting period (monthly, quarterly, annual) at a given reporting level (system, circuit, substation, PUC territory). Stores total customer minutes interrupted, total interruptions, customers served, MED-excluded values, and IEEE 1366 normalized values. This is the authoritative operational record — NOT an analytics aggregate — used for PUC regulatory filings and NERC reliability reporting.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`prediction` (
    `prediction_id` BIGINT COMMENT 'Unique surrogate identifier for the outage prediction record. Primary key for this entity in the Silver Layer lakehouse.',
    `ami_head_end_id` BIGINT COMMENT 'Foreign key linking to metering.ami_head_end. Business justification: Outage predictions consume AMI last-gasp data aggregated by head-end system. prediction has ami_meter_count but no FK to ami_head_end. Linking supports AMI-based predictive outage analytics, head-end ',
    `cause_id` BIGINT COMMENT 'Foreign key linking to outage.cause. Business justification: The prediction table has predicted_cause_code (STRING) and predicted_cause_description (STRING) as denormalized cause references. The cause table is the authoritative reference for outage cause classi',
    `distribution_substation_id` BIGINT COMMENT 'Identifier of the substation associated with the predicted outage scope. Used for crew dispatch routing and switching order coordination.',
    `load_id` BIGINT COMMENT 'Foreign key linking to forecast.load. Business justification: Predictive outage management systems integrate load forecasts to estimate customer impact (count, MW interrupted) and prioritize response. Advanced OMS platforms reference specific load forecast runs ',
    `event_id` BIGINT COMMENT 'Externally-known identifier assigned by the Outage Management System (OMS) to the predicted outage event. Used to correlate this prediction record with the OMS event lifecycle and downstream actual outage records.',
    `feeder_id` BIGINT COMMENT 'Identifier of the primary distribution circuit predicted to be affected by the outage. Sourced from the GIS network model and used for crew routing and switching order preparation.',
    `prediction_feeder_id` BIGINT COMMENT 'Identifier of the distribution feeder predicted to be affected. A feeder is a primary distribution line segment fed from a substation bus. Used for network topology analysis and switching order preparation.',
    `model_id` BIGINT COMMENT 'Identifier of the predictive analytics model version that generated this prediction, when prediction_source is predictive_model. Enables model performance tracking, auditability, and retraining feedback loops.',
    `service_territory_id` BIGINT COMMENT 'Reference to the regulated service territory within which the predicted outage falls. Used for regulatory reporting to State Public Utility Commissions (PUCs) and SAIDI/SAIFI/CAIDI performance tracking.',
    `state_estimation_run_id` BIGINT COMMENT 'Foreign key linking to grid.state_estimation_run. Business justification: Outage predictions use the current network state from state estimation as input to predictive models. The state estimation run provides the baseline network topology for fault location prediction. Dom',
    `storm_event_id` BIGINT COMMENT 'Reference to the storm or major weather event record associated with this prediction, if applicable. Links the prediction to the storm response management workflow for resource mobilization and regulatory major event day (MED) classification.',
    `weather_input_id` BIGINT COMMENT 'Foreign key linking to forecast.weather_input. Business justification: Outage prediction models consume weather forecast inputs (wind speed, precipitation, temperature) to predict storm-related outage likelihood and severity. Utilities use this linkage for storm prepared',
    `ami_meter_count` STRING COMMENT 'Number of Advanced Metering Infrastructure (AMI) smart meters within the predicted outage scope that contributed last-gasp or ping-failure signals to the prediction. Indicates the AMI signal density supporting the prediction confidence.',
    `confidence_level_pct` DECIMAL(18,2) COMMENT 'Numeric confidence score (0.00–100.00) representing the models or systems certainty in the predicted outage scope, cause, and affected area. Higher values indicate greater confidence. Used to prioritize crew dispatch and ETR communication decisions.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this outage prediction record was first persisted in the data platform. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `crew_preplacement_flag` BOOLEAN COMMENT 'Indicates whether field crews have been pre-positioned based on this outage prediction prior to field confirmation of the actual outage. When True, crew dispatch records are linked to this prediction in the workforce management system.',
    `critical_customer_flag` BOOLEAN COMMENT 'Indicates whether the predicted outage scope includes one or more critical customers (e.g., hospitals, emergency services, life-support customers, large industrial accounts with SLA obligations). When True, triggers priority restoration protocols and mandatory customer notification.',
    `customer_call_count` STRING COMMENT 'Number of inbound customer outage calls received and clustered to generate or corroborate this prediction. Used to assess the customer-reported signal strength and prioritize crew dispatch.',
    `der_impact_flag` BOOLEAN COMMENT 'Indicates whether the predicted outage scope includes Distributed Energy Resources (DERs) such as rooftop solar, battery storage, or microgrids that may be islanded or require isolation procedures. When True, DERMS coordination is required.',
    `expiry_timestamp` TIMESTAMP COMMENT 'Date and time after which this prediction is considered stale and should no longer be used for crew dispatch or ETR communication without refresh. Typically set to a configurable window (e.g., 2 hours) after prediction_timestamp. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `flisr_eligible_flag` BOOLEAN COMMENT 'Indicates whether the predicted outage scope is within a network segment eligible for automated Fault Location, Isolation, and Service Restoration (FLISR) execution via the ADMS. When True, automated switching sequences may be initiated without manual dispatcher intervention.',
    `major_event_day_flag` BOOLEAN COMMENT 'Indicates whether this prediction is associated with a Major Event Day (MED) as defined by IEEE 1366. MED events are excluded from standard SAIDI/SAIFI/CAIDI calculations and reported separately to state PUCs and NERC.',
    `medical_baseline_customer_flag` BOOLEAN COMMENT 'Indicates whether the predicted outage scope includes customers enrolled in a medical baseline or life-support program. When True, triggers mandatory proactive notification and priority restoration per state PUC regulations.',
    `notification_sent_flag` BOOLEAN COMMENT 'Indicates whether an outage notification has been sent to affected customers based on this prediction. When True, the notification timestamp and channel are tracked in the customer notification log. Supports state PUC notification compliance reporting.',
    `notification_timestamp` TIMESTAMP COMMENT 'Date and time at which the first customer notification was dispatched based on this outage prediction. Used for state PUC compliance reporting on notification timeliness. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `outage_type` STRING COMMENT 'Classification of the predicted outage by its nature. unplanned = unexpected equipment or system failure; planned = scheduled maintenance window; storm = weather-driven event; momentary = predicted to be a brief interruption (< 5 minutes per IEEE 1366); sustained = predicted to exceed the momentary threshold.. Valid values are `unplanned|planned|storm|momentary|sustained`',
    `predicted_affected_segments` STRING COMMENT 'Comma-delimited list of distribution circuit segment identifiers predicted to be de-energized. Sourced from the GIS network model topology analysis. Used for switching order preparation and crew routing.',
    `predicted_customer_count` STRING COMMENT 'Estimated number of customers predicted to be without power based on the initial assessment. Used for crew pre-positioning, ETR communication, and SAIDI/SAIFI/CAIDI impact estimation. Distinct from the confirmed customer count on the actual outage event record.',
    `predicted_etr` TIMESTAMP COMMENT 'Initial estimated date and time by which power is predicted to be restored to affected customers. Communicated to customers and field crews at the time of prediction creation. Distinct from the revised ETR updated during active restoration. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `predicted_fault_latitude` DECIMAL(18,2) COMMENT 'WGS-84 decimal latitude coordinate of the predicted fault location. Used for GIS-based crew dispatch and outage mapping.',
    `predicted_fault_location` STRING COMMENT 'Predicted geographic or network location of the fault, expressed as a GIS asset identifier, address, or coordinate reference. Used to direct first-responder crews to the most probable fault point before field confirmation.',
    `predicted_fault_longitude` DECIMAL(18,2) COMMENT 'WGS-84 decimal longitude coordinate of the predicted fault location. Used for GIS-based crew dispatch and outage mapping.',
    `predicted_load_mw` DECIMAL(18,2) COMMENT 'Estimated megawatts (MW) of load predicted to be interrupted based on the affected circuit segments and customer mix. Used for grid operations impact assessment and load restoration prioritization.',
    `predicted_outage_duration_min` STRING COMMENT 'Estimated duration of the outage in minutes as assessed at the time of prediction creation. Derived from historical restoration times for similar cause codes and circuit configurations. Used for CAIDI estimation and crew resource planning.',
    `prediction_source` STRING COMMENT 'The originating signal or mechanism that triggered the outage prediction. ami_ping = Advanced Metering Infrastructure (AMI) last-gasp or ping failure; scada_alarm = SCADA system alarm from field device; customer_call_cluster = clustering of inbound customer outage calls; predictive_model = ML/analytics model output; dispatcher_manual = manually entered by a system operator or dispatcher; smart_meter_outage_notification = direct outage notification from smart meter.. Valid values are `ami_ping|scada_alarm|customer_call_cluster|predictive_model|dispatcher_manual|smart_meter_outage_notification`',
    `prediction_status` STRING COMMENT 'Current lifecycle state of the outage prediction record. pending = generated but not yet dispatched; active = in use for crew pre-positioning and ETR communication; confirmed = field crew has validated the predicted scope; superseded = replaced by a newer prediction; cancelled = prediction voided before confirmation; expired = prediction window elapsed without field confirmation.. Valid values are `pending|active|confirmed|superseded|cancelled|expired`',
    `prediction_timestamp` TIMESTAMP COMMENT 'The date and time at which the outage prediction was system-generated or dispatcher-created. Represents the principal real-world event time for this prediction record. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `predictive_model_version` STRING COMMENT 'Version string of the predictive analytics model that generated this prediction. Used alongside predictive_model_id for model governance, auditability, and performance benchmarking.',
    `protection_zone` STRING COMMENT 'The protection zone or relay zone within which the predicted fault is located. Used by switching order coordinators to identify the correct protective device (recloser, fuse, breaker) to operate for isolation and restoration.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record that originated this outage prediction record. Used for data lineage, reconciliation, and Silver Layer provenance tracking.. Valid values are `GE_POWERON_ADMS|OSI_PI|ORACLE_MDM|SAP_ISU|MANUAL`',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this outage prediction record was last modified in the data platform. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `voltage_level` STRING COMMENT 'Voltage classification of the network segment predicted to be affected. Determines the severity tier, crew qualification requirements, and regulatory reporting category.. Valid values are `transmission|sub_transmission|primary_distribution|secondary_distribution`',
    `weather_condition_code` STRING COMMENT 'Standardized code representing the weather conditions at the time of prediction creation (e.g., clear, wind, ice, lightning, flood). Used for cause analysis, storm classification, and reliability reporting. [ENUM-REF-CANDIDATE: clear|wind|ice|lightning|flood|snow|extreme_heat|fog|tornado|hurricane — promote to reference product]',
    `wind_speed_mph` DECIMAL(18,2) COMMENT 'Recorded or forecast wind speed in miles per hour at the predicted fault location at the time of prediction creation. Used for storm severity assessment and major event day (MED) classification.',
    CONSTRAINT pk_prediction PRIMARY KEY(`prediction_id`)
) COMMENT 'Operational record of a system-generated or dispatcher-created predicted outage scope at the time of initial event creation, capturing estimated number of affected customers, predicted cause, predicted affected circuit segments, confidence level, and prediction source (AMI ping, SCADA alarm, customer call clustering, predictive model). Distinct from the actual outage event — represents the initial assessment used for crew pre-positioning and ETR communication before field confirmation.';

CREATE OR REPLACE TABLE `energy_utilities_ecm`.`outage`.`call` (
    `call_id` BIGINT COMMENT 'Unique surrogate identifier for each inbound customer trouble call or AMI-generated outage report record in the Outage Management System (OMS). Primary key for this entity.',
    `account_id` BIGINT COMMENT 'Reference to the utility customer account associated with the caller or AMI device that originated this outage report. Links to the Customer Information System (CIS) account record.',
    `der_system_id` BIGINT COMMENT 'Foreign key linking to interconnection.der_system. Business justification: Trouble calls from DER customers may indicate system malfunction, islanding issues, or anti-islanding protection failures requiring DER system reference for proper diagnosis and dispatch prioritizatio',
    `distribution_substation_id` BIGINT COMMENT 'Identifier of the distribution substation serving the reported outage location, resolved from the GIS network model. Used for geographic grouping of calls, outage event scoping, and storm response coordination.',
    `duplicate_of_call_id` BIGINT COMMENT 'Reference to the original (first-received) outage call record of which this call is a duplicate. Populated only when is_duplicate = True. Enables deduplication lineage tracing in OMS call clustering.',
    `event_id` BIGINT COMMENT 'Reference to the parent outage event record once this call has been matched or clustered to a confirmed outage event in the OMS. Null until the call is correlated to an event.',
    `feeder_id` BIGINT COMMENT 'Identifier of the distribution circuit (feeder) serving the reported outage location, resolved from the GIS network model based on the service address or premise. Used for OMS call clustering by circuit and outage event correlation.',
    `meter_id` BIGINT COMMENT 'Reference to the smart meter or AMI endpoint that generated an automated outage ping or last-gasp signal, if the call source is AMI-initiated rather than a human caller.',
    `premise_id` BIGINT COMMENT 'Reference to the utility service premise (physical delivery point) associated with the reported outage location. Links to the GIS/network model for spatial outage clustering and distribution circuit identification.',
    `storm_event_id` BIGINT COMMENT 'Reference to the declared storm or major weather event record associated with this outage call, when weather_event_flag = True. Links to the storm event management entity for storm response coordination and MED exclusion processing.',
    `affected_customers_reported` STRING COMMENT 'Number of customers the caller reports as being affected by the outage (e.g., my whole street is out). This is a caller-provided estimate, not a system-confirmed count. Used as an early indicator for outage scope assessment and crew dispatch prioritization.',
    `ami_device_code` STRING COMMENT 'Unique identifier of the AMI endpoint (smart meter) that generated an automated last-gasp outage notification or power-off ping. Populated only when call_source_type = AMI_PING. Used to correlate AMI-detected outages with customer account and network topology.',
    `ami_signal_type` STRING COMMENT 'Type of automated signal received from the AMI endpoint that triggered this outage report. LAST_GASP = meter-detected power loss notification; POWER_RESTORE = meter-detected power restoration; TAMPER = tamper event; BLINK = momentary interruption blink count; POWER_QUALITY = voltage sag/swell event. Populated only when call_source_type = AMI_PING.. Valid values are `LAST_GASP|POWER_RESTORE|TAMPER|BLINK|POWER_QUALITY`',
    `call_status` STRING COMMENT 'Current lifecycle status of the outage call record within the OMS workflow. RECEIVED = call logged, not yet processed; PENDING_MATCH = awaiting correlation to an outage event; MATCHED = successfully linked to an outage event; DUPLICATE = identified as a duplicate of an existing call or event; CLOSED = call resolved and closed; CANCELLED = call withdrawn or invalid.. Valid values are `RECEIVED|PENDING_MATCH|MATCHED|DUPLICATE|CLOSED|CANCELLED`',
    `caller_name` STRING COMMENT 'Full name of the individual who placed the trouble call, as provided at time of call. May differ from the account holder name if a third party is reporting on behalf of the customer. Classified as confidential PII per GDPR/CCPA.',
    `caller_phone_number` STRING COMMENT 'Phone number provided by or captured from the caller at time of call receipt. Used for call-back confirmation and customer notification of restoration. Classified as restricted PII per GDPR/CCPA.. Valid values are `^+?[0-9s-().]{7,20}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time at which this outage call record was first created in the data platform (Silver Layer ingestion timestamp). Serves as the audit creation timestamp for data lineage and regulatory record-keeping. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `customer_class` STRING COMMENT 'Classification of the customer associated with this outage call by service type. Used for restoration prioritization, regulatory reporting, and SAIDI/SAIFI index segmentation per IEEE 1366 and PUC requirements.. Valid values are `RESIDENTIAL|COMMERCIAL|INDUSTRIAL|AGRICULTURAL|MUNICIPAL`',
    `data_quality_flag` STRING COMMENT 'Indicates the data quality status of this outage call record as assessed during Silver Layer ingestion and validation. VALID = passed all validation rules; SUSPECT = passed ingestion but has anomalies requiring review; INVALID = failed critical validation; PENDING_REVIEW = awaiting manual data quality review.. Valid values are `VALID|SUSPECT|INVALID|PENDING_REVIEW`',
    `disposition_code` STRING COMMENT 'Standardized code indicating the final outcome or resolution action taken on this call (e.g., EVENT_CREATED, ADDED_TO_EVENT, DUPLICATE_CLOSED, NO_OUTAGE_FOUND, REFERRED_TO_CREW, CUSTOMER_CALLBACK_SCHEDULED). Sourced from OMS disposition reference table. [ENUM-REF-CANDIDATE: EVENT_CREATED|ADDED_TO_EVENT|DUPLICATE_CLOSED|NO_OUTAGE_FOUND|REFERRED_TO_CREW|CUSTOMER_CALLBACK_SCHEDULED|INVALID — promote to reference product]',
    `duration_seconds` STRING COMMENT 'Duration of the customer call in seconds from answer to disconnect, for calls received via IVR or live agent channels. Used for call center operational reporting, SLA (Service Level Agreement) compliance, and customer experience analytics.',
    `estimated_restoration_timestamp` TIMESTAMP COMMENT 'Estimated date and time of power restoration communicated to the customer at the time of call handling or subsequent notification. Sourced from OMS restoration forecasting. Used for customer expectation management and SLA (Service Level Agreement) tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `hazard_indicator` BOOLEAN COMMENT 'Indicates whether the caller reported a safety hazard associated with the outage (e.g., downed power line, sparking equipment, fire, flooding near electrical equipment). True = hazard reported; False = no hazard reported. Triggers priority escalation in OMS crew dispatch and public safety notification workflows.',
    `hazard_type` STRING COMMENT 'Specific type of safety hazard reported by the caller when hazard_indicator = True. Used to determine emergency response protocol, crew safety briefing requirements, and coordination with emergency services (fire, police). [ENUM-REF-CANDIDATE: DOWNED_LINE|SPARKING|FIRE|FLOODING|EQUIPMENT_DAMAGE|TREE_ON_LINE|VEHICLE_ACCIDENT|OTHER — promote to reference product]',
    `is_duplicate` BOOLEAN COMMENT 'Indicates whether this call has been identified as a duplicate report of an outage already captured by a prior call or AMI notification for the same event and location. True = duplicate; False = unique first report. Used by OMS call clustering logic to avoid double-counting in reliability metrics.',
    `ivr_session_code` STRING COMMENT 'Unique session identifier assigned by the Interactive Voice Response (IVR) system for calls received through the automated phone channel. Used for call traceability, IVR system reconciliation, and customer experience analytics. Populated only when call_source_type = IVR.',
    `matched_timestamp` TIMESTAMP COMMENT 'Date and time at which this call was successfully matched or correlated to a confirmed outage event in the OMS. Populated when call_status transitions to MATCHED. Used for OMS processing latency analysis and reliability reporting timelines. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `medical_baseline_flag` BOOLEAN COMMENT 'Indicates whether the affected customer account is registered on the utilitys medical baseline or life-support program, requiring priority restoration and proactive notification per PUC regulations. True = medical baseline customer; False = standard customer. Classified as confidential due to sensitivity of health-related program enrollment.',
    `notification_sent_flag` BOOLEAN COMMENT 'Indicates whether an outage acknowledgement or estimated restoration time (ERT) notification has been sent to the customer associated with this call. True = notification sent; False = not yet sent. Supports PUC customer notification compliance tracking.',
    `notification_timestamp` TIMESTAMP COMMENT 'Date and time at which the outage acknowledgement or estimated restoration time (ERT) notification was dispatched to the customer. Populated when notification_sent_flag = True. Used for PUC notification compliance reporting. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `oms_call_cluster_code` STRING COMMENT 'Identifier of the OMS call cluster to which this call has been assigned during the outage prediction and event correlation process. Multiple calls from the same geographic area or circuit are grouped into a cluster to predict the probable outage location and initiate crew dispatch before a formal event is confirmed.',
    `outage_start_reported_timestamp` TIMESTAMP COMMENT 'Date and time the caller reports the outage began, as stated by the customer or detected by the AMI device. May differ from the OMS-confirmed outage start time. Used as an input to outage event timeline reconstruction and SAIDI/CAIDI calculations. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `priority_level` STRING COMMENT 'Restoration priority level assigned to this outage call based on hazard indicators, medical baseline status, customer class, and outage scope. CRITICAL = life-safety or critical infrastructure; HIGH = medical baseline or large commercial/industrial; MEDIUM = standard residential or small commercial; LOW = non-urgent or duplicate. Drives OMS crew dispatch sequencing.. Valid values are `CRITICAL|HIGH|MEDIUM|LOW`',
    `received_timestamp` TIMESTAMP COMMENT 'Date and time at which the outage call or AMI-generated outage report was received by the utility system. This is the principal business event timestamp used for OMS call clustering, outage prediction, and SAIDI/SAIFI/CAIDI reliability index calculations. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `reference_number` STRING COMMENT 'Externally visible alphanumeric reference number assigned to this trouble call at receipt, used for customer-facing acknowledgement (e.g., IVR confirmation code, agent ticket number, web portal confirmation). Sourced from the CIS or OMS call intake module.',
    `reported_symptom_code` STRING COMMENT 'Standardized code representing the symptom or problem reported by the caller or detected by the AMI system (e.g., FULL_OUTAGE, PARTIAL_OUTAGE, FLICKERING, LOW_VOLTAGE, DOWNED_LINE, BURNING_SMELL). Sourced from the OMS symptom code reference table. [ENUM-REF-CANDIDATE: FULL_OUTAGE|PARTIAL_OUTAGE|FLICKERING|LOW_VOLTAGE|DOWNED_LINE|BURNING_SMELL|SPARKING|BUZZING — promote to reference product]',
    `reported_symptom_description` STRING COMMENT 'Free-text description of the outage symptom or problem as reported by the caller or transcribed by the call center agent. Supplements the structured symptom code with verbatim customer language for OMS analysis and crew dispatch context.',
    `service_address` STRING COMMENT 'Street address of the service location reported as experiencing the outage, as provided by the caller or resolved from the account record. Used for geographic clustering in the OMS and crew dispatch routing.',
    `service_territory_code` STRING COMMENT 'Code identifying the utilitys regulated service territory or operating division in which the reported outage is located. Used for regulatory reporting segmentation to State PUCs and NERC reliability reporting.',
    `source_system_call_code` STRING COMMENT 'Original call or ticket identifier assigned by the source operational system (e.g., OMS call number from GE PowerOn ADMS, CIS interaction ID from SAP IS-U or Oracle CC&B). Enables traceability and reconciliation between the Silver Layer data product and the system of record.',
    `source_type` STRING COMMENT 'Channel or mechanism through which the outage report was received. IVR = Interactive Voice Response automated phone system; AGENT = live call center agent; AMI_PING = Advanced Metering Infrastructure last-gasp or outage notification; MOBILE_APP = utility mobile application; WEB_PORTAL = online self-service portal; FIELD_CREW = field crew-initiated report.. Valid values are `IVR|AGENT|AMI_PING|MOBILE_APP|WEB_PORTAL|FIELD_CREW`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time at which this outage call record was last modified in the data platform, reflecting any status updates, event matching, or data corrections applied during the call lifecycle. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `weather_event_flag` BOOLEAN COMMENT 'Indicates whether the outage reported in this call is associated with a declared weather event (storm, hurricane, ice storm, heat wave, etc.). True = weather-related; False = non-weather. Relevant for IEEE 1366 Major Event Day (MED) exclusion determination and storm response activation.',
    CONSTRAINT pk_call PRIMARY KEY(`call_id`)
) COMMENT 'Record of an inbound customer trouble call or AMI-generated outage report received by the utility, used to initiate or corroborate an outage event. Captures call receipt timestamp, source type (IVR, agent, AMI ping, mobile app, web portal), reported symptom, caller account reference, associated outage event (once matched), call disposition, and whether the call was a duplicate of an existing event. Feeds OMS call clustering and outage prediction logic.';

